package pi

import (
	_ "embed"
	"fmt"

	"github.com/goccy/go-yaml"

	"github.com/agent-sync/agent-sync/internal/capmatrix"
	"github.com/agent-sync/agent-sync/internal/ir"
	"github.com/agent-sync/agent-sync/pkg/adapterkit"
)

//go:embed capabilities.yaml
var capabilitiesYAML []byte

// declarationFile is the parsed shape of capabilities.yaml.
type declarationFile struct {
	Name            string                            `yaml:"name"`
	Version         string                            `yaml:"version"`
	ContractVersion string                            `yaml:"contract_version"`
	ReservedPrefix  string                            `yaml:"reserved_prefix"`
	ConceptKinds    map[string]conceptKindDeclaration `yaml:"concept_kinds"`
}

type conceptKindDeclaration struct {
	Status capmatrix.CapabilityStatus `yaml:"status"`
	Note   string                     `yaml:"note,omitempty"`
}

// conceptKinds is the in-code mirror of capabilities.yaml. The unit test
// asserts the two are kept in sync.
//
// Pi declares two kinds supported (agents-md, skill) and four unsupported. MCP
// and rule are deliberate Pi product exclusions; command is planned (Pi's
// prompt dir is flat + shared, needing file-leaf swap support). Skills land in
// the shared .agents/skills tree, co-owned with codex — made safe by the
// engine's union-aware drift/orphan checks (ADV-1). See capabilities.yaml notes
// and docs/adapters/pi.md.
var conceptKinds = map[ir.Kind]capmatrix.CapabilityStatus{
	ir.KindAgentsMD:        capmatrix.Supported,
	ir.KindSkill:           capmatrix.Supported,
	ir.KindCommand:         capmatrix.Unsupported,
	ir.KindMCPServerEntry:  capmatrix.Unsupported,
	ir.KindRule:            capmatrix.Unsupported,
	ir.KindPluginReference: capmatrix.Unsupported,
}

// capabilitiesForWire returns the adapterkit.Capabilities the adapter echoes in
// its initialize response. WriteToolOwned is true because pi emits a
// write_tool_owned op for the AGENTS.md managed section.
//
// Unlike cursor, pi's capability set does not vary by scope: every supported
// kind (agents-md, skill) has a user-global home, so nothing is demoted at user
// scope. Only the agents-md output path is scope-aware (see declaredOutputs).
func capabilitiesForWire() adapterkit.Capabilities {
	builder := adapterkit.NewCapabilities().WithWriteToolOwned(true)
	for kind, status := range conceptKinds {
		switch status {
		case capmatrix.Supported:
			builder.Supports(string(kind))
		case capmatrix.Partial:
			builder.Partial(string(kind))
		case capmatrix.Unsupported:
			builder.Unsupported(string(kind))
		}
	}
	return builder.Build()
}

// declaredOutputs returns the list the adapter advertises in its initialize
// response. The runtime path-safety gate (pathInDeclaredOutputs) accepts an
// emitted op only when its path falls inside one of these declared outputs.
//
// Pi owns no single reserved subdirectory: skills go under the shared
// .agents/skills/ tree, and prose into the tool-owned AGENTS.md. The agents-md
// path is scope-aware — at user scope Pi reads ~/.pi/agent/AGENTS.md, so the
// adapter targets .pi/agent/AGENTS.md there. Both declared and emitted paths
// resolve from resolvePathSet so they never drift. See plan
// docs/plans/2026-06-30-003.
func declaredOutputs(scope string) []adapterkit.DeclaredOutput {
	agentsMDSection := "agent-sync"
	paths := resolvePathSet(scope)
	return []adapterkit.DeclaredOutput{
		// .agents/skills is the shared cross-tool skills tree (pi, codex, and
		// the user all place skills here). shared-subdir → the engine manages
		// only the agent-sync-<id> leaf dirs, never the parent, so foreign
		// skills and sibling-adapter skills survive a sync (ADV-1 co-ownership).
		{Path: skillsParent, Mode: adapterkit.OutputModeSharedSubdir},
		{Path: paths.agentsMD, Mode: adapterkit.OutputModeToolOwnedEntry, SectionID: &agentsMDSection},
	}
}

// parseCapabilitiesYAML decodes the embedded YAML. Used by the parity test and
// by callers that want the human-readable note bodies.
func parseCapabilitiesYAML(src []byte) (declarationFile, error) {
	var d declarationFile
	if err := yaml.UnmarshalWithOptions(
		src,
		&d,
		yaml.DisallowUnknownField(),
		yaml.AllowFieldPrefixes("x-"),
	); err != nil {
		return declarationFile{}, fmt.Errorf("pi: parse capabilities.yaml: %s", yaml.FormatError(err, false, true))
	}
	return d, nil
}

// loadDeclaration parses the embedded capabilities.yaml and returns the result.
func loadDeclaration() (declarationFile, error) {
	return parseCapabilitiesYAML(capabilitiesYAML)
}

package claude

import (
	_ "embed"
	"fmt"

	"github.com/goccy/go-yaml"

	"github.com/agent-sync/agent-sync/internal/capmatrix"
	"github.com/agent-sync/agent-sync/internal/ir"
	"github.com/agent-sync/agent-sync/pkg/adapterkit"
)

//go:embed capabilities.yaml
var capabilitiesYAML []byte

// declarationFile is the parsed shape of capabilities.yaml. It is
// intentionally narrower than adapter.AdapterManifest so the file
// stays a per-adapter declaration and not an arbitrary manifest
// override.
type declarationFile struct {
	Name            string                            `yaml:"name"`
	Version         string                            `yaml:"version"`
	ContractVersion string                            `yaml:"contract_version"`
	ReservedPrefix  string                            `yaml:"reserved_prefix"`
	ConceptKinds    map[string]conceptKindDeclaration `yaml:"concept_kinds"`
}

type conceptKindDeclaration struct {
	Status capmatrix.CapabilityStatus `yaml:"status"`
	Note   string                     `yaml:"note,omitempty"`
}

// conceptKinds is the in-code mirror of capabilities.yaml. The unit
// test asserts the two are kept in sync; if you add a kind here,
// add it there (and vice versa).
//
// The status values use capmatrix's vocabulary; the wire conversion
// happens in capabilitiesForWire.
var conceptKinds = map[ir.Kind]capmatrix.CapabilityStatus{
	ir.KindAgentsMD:        capmatrix.Supported,
	ir.KindRule:            capmatrix.Supported,
	ir.KindSkill:           capmatrix.Supported,
	ir.KindCommand:         capmatrix.Supported,
	ir.KindMCPServerEntry:  capmatrix.Supported,
	ir.KindPluginReference: capmatrix.Unsupported,
}

// capabilitiesForWire returns the adapterkit.Capabilities the adapter
// echoes in its initialize response. WriteToolOwned is true because
// the claude adapter emits write_tool_owned ops for .mcp.json and
// CLAUDE.md.
func capabilitiesForWire() adapterkit.Capabilities {
	builder := adapterkit.NewCapabilities().WithWriteToolOwned(true)
	for kind, status := range conceptKinds {
		switch status {
		case capmatrix.Supported:
			builder.Supports(string(kind))
		case capmatrix.Partial:
			builder.Partial(string(kind))
		case capmatrix.Unsupported:
			builder.Unsupported(string(kind))
		}
	}
	return builder.Build()
}

// declaredOutputs returns the list the adapter advertises in its
// initialize response. The runtime path-safety gate
// (internal/adapter/runtime.go pathInDeclaredOutputs) accepts an
// emitted op only when its path falls inside one of these declared
// outputs.
func declaredOutputs(scope string) []adapterkit.DeclaredOutput {
	mcpPointer := "/mcpServers"
	claudeMDSection := "agent-sync"
	// The two tool-owned-entry paths and the sidecar are scope-resolved from
	// the same source as the emit paths (emit_tool_owned.go resolvePathSet),
	// so declared and emitted paths never drift — the path-safety gate
	// (runtime.go pathInDeclaredOutputs) rejects any mismatch.
	paths := resolvePathSet(scope)
	outs := []adapterkit.DeclaredOutput{
		{Path: ".claude/rules/agent-sync", Mode: adapterkit.OutputModeOwnedSubdir},
		{Path: ".claude/commands/agent-sync", Mode: adapterkit.OutputModeOwnedSubdir},
		// .claude/skills holds agent-sync-<id> leaf dirs alongside the user's own
		// skills. shared-subdir → manage only our leaves, never the parent, so
		// user skills survive a sync. (.claude/rules/agent-sync and
		// .claude/commands/agent-sync are agent-sync-exclusive, so they stay
		// owned-subdir and are swapped wholesale.) These already land under
		// .claude/ and so are correct at user scope too — unchanged here.
		{Path: ".claude/skills", Mode: adapterkit.OutputModeSharedSubdir},
		{Path: paths.mcpJSON, Mode: adapterkit.OutputModeToolOwnedEntry, JSONPointer: &mcpPointer},
		{Path: paths.claudeMD, Mode: adapterkit.OutputModeToolOwnedEntry, SectionID: &claudeMDSection},
	}
	// The strict-JSON sidecar marker is written next to an agent-sync-owned
	// strict-JSON file at project/directory scope. At user scope the MCP target
	// is Claude's own ~/.claude.json (paths.sidecar == ""), so it is neither
	// declared nor emitted.
	if paths.sidecar != "" {
		outs = append(outs, adapterkit.DeclaredOutput{Path: paths.sidecar, Mode: adapterkit.OutputModeOwnedSubdir})
	}
	return outs
}

// parseCapabilitiesYAML decodes the embedded YAML. Used by the parity
// test and by callers that want the human-readable note bodies.
func parseCapabilitiesYAML(src []byte) (declarationFile, error) {
	var d declarationFile
	if err := yaml.UnmarshalWithOptions(
		src,
		&d,
		yaml.DisallowUnknownField(),
		yaml.AllowFieldPrefixes("x-"),
	); err != nil {
		return declarationFile{}, fmt.Errorf("claude: parse capabilities.yaml: %s", yaml.FormatError(err, false, true))
	}
	return d, nil
}

// loadDeclaration parses the embedded capabilities.yaml and returns
// the result. Cached at package level if it ever becomes a hot path;
// for now the call sites are test-only and one-off.
func loadDeclaration() (declarationFile, error) {
	return parseCapabilitiesYAML(capabilitiesYAML)
}

package claude

import (
	"bytes"
	"encoding/json"
	"fmt"

	"github.com/agent-sync/agent-sync/pkg/adapterkit"
)

const (
	mcpJSONPath        = ".mcp.json"
	mcpJSONPointerBase = "/mcpServers/agentsync_"
	claudeMDPath       = "CLAUDE.md"
	claudeMDSidecar    = ".agent-sync-managed"
	sectionIDPrefix    = "agent-sync:"

	// scopeUser is the wire value (hierarchy.Level.String()) for the
	// user-home scope. Any other value (incl. "" / "project" / "directory")
	// is treated as project scope.
	scopeUser = "user"
)

// pathSet holds the scope-resolved destinations for the Claude adapter's two
// tool-owned-entry outputs and the strict-JSON sidecar. At project/directory
// scope they are workspace-root files (the historical behavior). At user
// scope they target Claude Code's real user-config paths — `~/.claude/CLAUDE.md`
// and `~/.claude.json` (relative to the home scope root) — and the sidecar is
// suppressed, because `~/.claude.json` is Claude's own shared file, not an
// agent-sync-owned strict-JSON file the marker may claim.
type pathSet struct {
	claudeMD string
	mcpJSON  string
	sidecar  string // "" ⇒ do not declare/emit the sidecar (user scope)
}

// resolvePathSet maps the initialize scope to the adapter's tool-owned paths.
// Declared outputs (capabilities.go) and emitted op paths (here) MUST resolve
// from this one function so they never drift — a mismatch is rejected by the
// runtime's path-safety gate.
func resolvePathSet(scope string) pathSet {
	if scope == scopeUser {
		return pathSet{claudeMD: ".claude/CLAUDE.md", mcpJSON: ".claude.json", sidecar: ""}
	}
	return pathSet{claudeMD: claudeMDPath, mcpJSON: mcpJSONPath, sidecar: claudeMDSidecar}
}

// markerOpenBytes is the literal HTML-comment opener every agent-sync
// section marker uses. Body content for an agents-md node is rejected
// when it contains this byte sequence: a hostile body could otherwise
// inject a fake end-marker followed by a fake begin-marker, splitting
// the managed section in CLAUDE.md and confusing the merge step.
var markerOpenBytes = []byte("<!-- agent-sync:")

// emitMCPServerEntry emits one write_tool_owned op into .mcp.json
// at /mcpServers/agentsync_<id>, plus a sidecar .agent-sync-managed marker
// (deduplicated per emit) that advertises ownership next to the
// strict-JSON file.
//
// The body is required to parse as a JSON object. A scalar, array,
// or boolean body would corrupt the merged .mcp.json: Claude Code
// expects /mcpServers/<key> to map to an object with command/args
// fields, and storing a non-object value silently breaks every MCP
// load for the workspace.
//
// Validation is two-stage:
//  1. json.Valid — proves the bytes parse, catching string-encoded
//     bodies like "{" that look object-shaped at the first byte but
//     are actually unterminated JSON.
//  2. isJSONObject — proves the top-level structure is `{...}` and
//     not a number/array/bool/null that json.Valid alone would
//     accept.
func emitMCPServerEntry(emitted *emittedOps, node irNode, state *emitState) error {
	body, err := decodeBodyOrPassthrough(node.Body)
	if err != nil {
		return wrapBodyErr(node, err)
	}
	if !json.Valid(body) {
		return &adapterkit.Error{
			Code:    adapterkit.CodeInvalidParams,
			Message: fmt.Sprintf("claude: mcp-server-entry %q body is not valid JSON; refusing to corrupt %s", node.ID, state.paths.mcpJSON),
		}
	}
	if !isJSONObject(body) {
		return &adapterkit.Error{
			Code:    adapterkit.CodeInvalidParams,
			Message: fmt.Sprintf("claude: mcp-server-entry %q body must be a JSON object (got non-object)", node.ID),
		}
	}

	emitted.add(adapterkit.OpWriteToolOwned{
		Path:    state.paths.mcpJSON,
		Kind:    adapterkit.ToolOwnedKindJSONPointer,
		Locator: mcpJSONPointerBase + node.ID,
		Content: body,
	})

	// The sidecar advertises agent-sync ownership next to an agent-sync-owned
	// strict-JSON file. At user scope the MCP target is `~/.claude.json` —
	// Claude's own shared config — so paths.sidecar is empty and we suppress it.
	if state.paths.sidecar != "" && !state.sidecarEmitted {
		state.sidecarEmitted = true
		sidecar, err := adapterkit.NewOpWriteFile(state.paths.sidecar, 0o644, jsonSidecarMarker())
		if err != nil {
			return wrapOpErr(node, err)
		}
		emitted.add(sidecar)
	}
	return nil
}

// emitAgentsMD writes the agents-md companion overlay into
// CLAUDE.md (workspace root) as a managed section between
// <!-- agent-sync:begin id=<id> --> and <!-- agent-sync:end id=<id> -->
// markers. CLAUDE.md is tool-owned by Claude Code; user content
// outside the managed section is preserved by the merge step
// (Unit 12a).
//
// The engine owns the begin/end markers — it renders the managed block
// from the locator during the markdown-section merge. The adapter passes
// the INNER body only; sending marker-wrapped content is rejected by the
// merge ("the engine owns markers; pass inner body only"). This mirrors
// the cursor and codex adapters.
//
// The body is still rejected when it contains the agent-sync marker
// opener. Without this guard a body containing
// `<!-- agent-sync:end id=other -->` could forge another section,
// leaving the merged CLAUDE.md with conflicting markers the merge step
// has no way to resolve safely.
//
// No managed-file header is added inside the section: the begin/end
// markers serve as the equivalent ownership advertisement, and a
// header inside a user-owned markdown file would be visually noisy.
func emitAgentsMD(emitted *emittedOps, node irNode, state *emitState) error {
	body, err := decodeBodyOrPassthrough(node.Body)
	if err != nil {
		return wrapBodyErr(node, err)
	}
	if bytes.Contains(body, markerOpenBytes) {
		return &adapterkit.Error{
			Code:    adapterkit.CodeInvalidParams,
			Message: fmt.Sprintf("claude: agents-md %q body contains agent-sync marker syntax (%q); refusing to corrupt CLAUDE.md", node.ID, string(markerOpenBytes)),
		}
	}

	emitted.add(adapterkit.OpWriteToolOwned{
		Path:    state.paths.claudeMD,
		Kind:    adapterkit.ToolOwnedKindMarkdownSection,
		Locator: sectionIDPrefix + node.ID,
		Content: body,
	})
	return nil
}

// emitPluginReferenceWarning surfaces the unsupported declaration
// for a plugin-reference node. Claude Code does not load
// project-level plugin registries, so the adapter declines and
// surfaces a degradation warning the sync engine will report.
//
// No write_file is emitted. The runtime's capability-lied check
// (internal/adapter/runtime.go) only fires for kinds the adapter
// declared as `supported`, so emitting a warning-only result here
// is safe — plugin-reference is declared `unsupported` in
// capabilities.yaml.
func emitPluginReferenceWarning(emitted *emittedOps, node irNode) error {
	emitted.add(adapterkit.OpWarning{
		ConceptID: node.ID,
		Status:    adapterkit.WarningStatusDegraded,
		Note:      "Claude Code does not load project-level plugin-reference registries; install plugins via Claude Code's own plugin command",
	})
	return nil
}

// isJSONObject reports whether body is a JSON object (`{...}`),
// not a scalar, array, or null. Assumes the caller already verified
// the bytes are valid JSON via decodeBodyOrPassthrough; the check
// here is purely structural — first non-whitespace byte must be `{`.
func isJSONObject(body []byte) bool {
	for _, b := range body {
		switch b {
		case ' ', '\t', '\n', '\r':
			continue
		case '{':
			return true
		default:
			return false
		}
	}
	return false
}

package cli

import (
	"context"
	"errors"
	"fmt"
	"time"

	"github.com/agent-sync/agent-sync/internal/adapter"
	claudeadapter "github.com/agent-sync/agent-sync/internal/adapter/bundled/claude"
	codexadapter "github.com/agent-sync/agent-sync/internal/adapter/bundled/codex"
	cursoradapter "github.com/agent-sync/agent-sync/internal/adapter/bundled/cursor"
	piadapter "github.com/agent-sync/agent-sync/internal/adapter/bundled/pi"
	"github.com/agent-sync/agent-sync/internal/engine"
	"github.com/agent-sync/agent-sync/internal/fsroot"
	"github.com/agent-sync/agent-sync/internal/manifest"
	"github.com/agent-sync/agent-sync/internal/workspace"
)

// bundledAdapters returns the compiled-in adapter set. Centralized so
// every command discovers the same adapters.
func bundledAdapters() []*adapter.BundledAdapter {
	return []*adapter.BundledAdapter{
		claudeadapter.Bundled(),
		cursoradapter.Bundled(),
		codexadapter.Bundled(),
		piadapter.Bundled(),
	}
}

// prepared bundles the per-invocation engine inputs shared by sync and
// validate: an opened workspace root (the caller must Close it), the
// loaded manifest, and a fully-built engine.Request. Close releases the
// root.
type prepared struct {
	Workspace *workspace.Workspace
	Manifest  *manifest.Manifest
	Root      *fsroot.Root
	Request   engine.Request
	Close     func()

// Package coverage reports when a scope emits a node kind that a target tool
// will not read natively at that scope's hierarchy level.
//
// agent-sync resolves precedence by emitting each scope to its own filesystem
// location and letting the target tool's native config hierarchy apply it
// (see the hierarchy-aware-manifests design). That only works as far as each
// tool actually reads a given kind at a given level. This package encodes the
// known native-read behavior per target and flags the gaps so users are not
// silently surprised by emitted content that never takes effect.
//
// The native-support table is keyed by target NAME and is static: a read-only
// analyzer cannot run an adapter Initialize handshake to learn declared
// outputs, and external adapters cannot be queried at all. Unknown targets and
// unknown kinds default to native (no false warnings). The directory- and
// user-level entries are the project's documented assumptions about each tool's
// read behavior; correct them here if a tool's behavior is verified to differ.
package coverage

import (
	"sort"

	"github.com/agent-sync/agent-sync/internal/hierarchy"
	"github.com/agent-sync/agent-sync/internal/ir"
)

// Warning is one (target, kind, level) combination that will be emitted but
// not read natively by the target tool at that level.
type Warning struct {
	Target string
	Kind   ir.Kind
	Level  hierarchy.Level
	Detail string
}

// nativeAtDirectory[target] is the set of kinds the target reads natively from
// a NESTED directory. A kind absent from a target's set is non-native at the
// directory level and warns. The project level is always native (the tool reads
// its workspace-root config), so it is not represented here.
//
// Documented assumptions (verify against current tool behavior, correct here):
//   - claude reads nested CLAUDE.md (agents-md); it does NOT read rules,
//     commands, skills, or mcp entries from nested .claude/ directories.
//   - codex walks nested AGENTS.md (agents-md); nothing else nested.
//   - cursor reads nested .cursor/rules (rule); nothing else nested.
var nativeAtDirectory = map[string]map[ir.Kind]bool{
	"claude": {ir.KindAgentsMD: true},
	"codex":  {ir.KindAgentsMD: true},
	"cursor": {ir.KindRule: true},
}

// nonNativeAtUser[target] is the set of kinds the target does NOT read from any
// file-addressable user-global (home) location, so emitting them at user scope
// is inert. This is an inverted table from nativeAtDirectory: only targets with
// a user-scope gap appear, and an absent target/kind ⇒ native at user scope (no
// warning). Most tools read every supported kind from their user-global config
// (the user scope root is $HOME, so e.g. .codex/config.toml resolves to
// ~/.codex/config.toml), so they have no entry.
//
// Documented assumptions (verified against official docs 2026-06-30):
//   - cursor has no file-addressable user-global home for rules (User Rules
//     live in app settings / cloud, not a writable file) or AGENTS.md; only
//     ~/.cursor/mcp.json is file-addressable. So rule and agents-md are inert
//     at user scope.
//   - claude (scope-aware paths target ~/.claude/...) and codex (agents-md
//     remaps to ~/.codex/AGENTS.md; mcp + skills already resolve under $HOME)
//     read every supported kind from a user-global location → no entry.
var nonNativeAtUser = map[string]map[ir.Kind]bool{
	"cursor": {ir.KindRule: true, ir.KindAgentsMD: true},
}

// known reports whether we have a native-support table for target. Unknown
// targets default to fully native (no warnings).
func known(target string) bool {
	_, ok := nativeAtDirectory[target]
	return ok
}

// Analyze returns the coverage warnings for emitting the given kinds to the
// given targets at the given level. Results are deterministically ordered by
// target then kind. The project level never warns (every tool reads its
// workspace-root config); the directory level warns for kinds not read from a
// nested dir, and the user level warns for kinds with no file-addressable
// user-global home. Targets with no table never warn.
func Analyze(level hierarchy.Level, kinds []ir.Kind, targets []string) []Warning {
	var out []Warning
	switch level {
	case hierarchy.LevelDirectory:
		for _, target := range targets {
			if !known(target) {
				continue
			}
			nativeKinds := nativeAtDirectory[target]
			for _, k := range kinds {
				if nativeKinds[k] {
					continue
				}
				out = append(out, Warning{
					Target: target,
					Kind:   k,
					Level:  level,
					Detail: target + " does not read " + string(k) + " from a nested directory; this will not take effect until per-tool runtime mapping is added",
				})
			}
		}
	case hierarchy.LevelUser:
		for _, target := range targets {
			gap := nonNativeAtUser[target]
			if gap == nil {
				continue
			}
			for _, k := range kinds {
				if !gap[k] {
					continue
				}
				out = append(out, Warning{
					Target: target,
					Kind:   k,
					Level:  level,
					Detail: target + " has no user-global location for " + string(k) + "; emitted content is inert at user scope (sync it at project scope instead)",
				})
			}
		}
	default:
		return nil
	}
	sort.Slice(out, func(i, j int) bool {
		if out[i].Target != out[j].Target {
			return out[i].Target < out[j].Target
		}
		return out[i].Kind < out[j].Kind
	})
	return out
}

