228		case ir.KindMCPServerEntry:
229			return emitMCPServerEntry(emitted, node, state)
230		case ir.KindAgentsMD:
231			return emitAgentsMD(emitted, node, state)
232		case ir.KindPluginReference:
233			return emitPluginReferenceWarning(emitted, node)
