242	// decodeIRDocument unmarshals the EmitParams.IR raw message. Returns
243	// a wrapped error on parse failure so handleEmit can convert it to a
244	// JSON-RPC InvalidParams response.
245	func decodeIRDocument(raw json.RawMessage) (irDocument, error) {
246		if len(raw) == 0 {
247			return irDocument{}, nil
248		}
249		var doc irDocument
250		if err := json.Unmarshal(raw, &doc); err != nil {
251			return irDocument{}, fmt.Errorf("decode IR document: %w", err)
252		}
253		return doc, nil
254	}
