256	// nodeTargetsClaude reports whether the node's targets list either
257	// is empty (means "all adapters") or includes the claude adapter.
258	// IR-side validation guarantees the contained values are known
259	// adapter names; we don't re-validate here.
260	func nodeTargetsClaude(node irNode) bool {
261		if len(node.Targets) == 0 {
262			return true
263		}
264		for _, t := range node.Targets {
265			if t == adapterName {
266				return true
267			}
268		}
269		return false
270	}
