272	// rejectDuplicateNodes returns InvalidParams when the wire payload
273	// contains two or more nodes with the same (kind, id) pair. The
274	// fail-closed default avoids the silent last-write-wins behavior the
275	// sync engine would otherwise hit at write time.
276	func rejectDuplicateNodes(nodes []irNode) error {
277		seen := make(map[string]struct{}, len(nodes))
278		for _, n := range nodes {
279			key := n.Kind + "/" + n.ID
280			if _, dup := seen[key]; dup {
281				return &adapterkit.Error{
282					Code:    adapterkit.CodeInvalidParams,
283					Message: fmt.Sprintf("claude: duplicate node (kind=%q id=%q) in IR payload", n.Kind, n.ID),
284				}
285			}
286			seen[key] = struct{}{}
287		}
288		return nil
289	}
290	
291	// decodeBodyOrPassthrough turns a node or asset Body field into raw
292	// bytes. The wire shape allows two body encodings:
293	//   - JSON string (markdown bodies): `"# heading\n..."`
294	//   - Raw JSON value (json/toml kinds): `{"command":"node",...}`
295	//
296	// String-decode is tried first; if that fails the raw JSON value is
297	// validated and passed through unchanged.
298	func decodeBodyOrPassthrough(raw json.RawMessage) ([]byte, error) {
299		if len(raw) == 0 || string(raw) == "null" {
300			return nil, nil
301		}
302		var s string
303		if err := json.Unmarshal(raw, &s); err == nil {
304			return []byte(s), nil
305		}
306		var any any
307		if err := json.Unmarshal(raw, &any); err != nil {
308			return nil, fmt.Errorf("body must be a JSON string or valid JSON value: %w", err)
309		}
310		return raw, nil
311	}
312	
313	// wrapBodyErr converts a node-body decode error into the structured
314	// JSON-RPC error the caller returns.
315	func wrapBodyErr(node irNode, err error) error {
316		return &adapterkit.Error{
317			Code:    adapterkit.CodeInvalidParams,
318			Message: fmt.Sprintf("claude: node %q (%s) body: %s", node.ID, node.Kind, err.Error()),
319		}
320	}
321	
322	// wrapOpErr converts an op-construction error (typically the
323	// payload-too-large guard inside NewOpWriteFile) into the structured
324	// JSON-RPC error the caller returns.
325	func wrapOpErr(node irNode, err error) error {
326		return &adapterkit.Error{
327			Code:    adapterkit.CodeInvalidParams,
328			Message: fmt.Sprintf("claude: node %q (%s) op: %s", node.ID, node.Kind, err.Error()),
329		}
330	}
