11		"github.com/agent-sync/agent-sync/internal/adapter/bundled/skillmeta"
12		"github.com/agent-sync/agent-sync/pkg/adapterkit"
13	)
14	
15	const (
16		rulesSubdir    = ".claude/rules/agent-sync"
17		commandsSubdir = ".claude/commands/agent-sync"
18		skillsParent   = ".claude/skills"
19		skillPrefix    = "agent-sync-"
20		skillEntryFile = "SKILL.md"
21	)
22	
23	// emitRule maps one rule node to:
24	//   - mkdir(.claude/rules/agent-sync)            (deduped per-emit)
25	//   - write_file(.claude/rules/agent-sync/README.md)  (deduped per-emit)
26	//   - write_file(.claude/rules/agent-sync/<id>.md)
27	//   - warning op when the body opens with `paths:` frontmatter
28	//     (Claude Code activation behavior is inconsistent with that
29	//     frontmatter as of 2026-04).
30	//
31	// Rule of Three: emitRule and emitCommand are structurally identical;
32	// only the subdir constant varies. Collapse to a shared
33	// emitReservedSubdirNode helper when the third reserved-subdirectory
34	// kind appears (Unit 10 cursor adds a second; Unit 11 codex would be
35	// the third — re-evaluate then).
36	func emitRule(emitted *emittedOps, node irNode, state *emitState) error {
37		body, err := decodeBodyOrPassthrough(node.Body)
38		if err != nil {
39			return wrapBodyErr(node, err)
40		}
41	
42		if err := ensureSubdir(emitted, rulesSubdir, state); err != nil {
43			return err
44		}
45	
46		rulePath := rulesSubdir + "/" + node.ID + ".md"
47		if err := state.recordWritePath(rulePath); err != nil {
48			return err
49		}
50		wf, err := adapterkit.NewOpWriteFile(rulePath, 0o644, prependHeader(state, node, body))
51		if err != nil {
52			return wrapOpErr(node, err)
53		}
54		emitted.add(wf)
55	
56		if hasPathsFrontmatter(body) {
57			emitted.add(adapterkit.OpWarning{
58				ConceptID: node.ID,
59				Status:    adapterkit.WarningStatusDegraded,
60				Note:      "rule has paths: frontmatter — Claude Code activation behavior is inconsistent with that field as of 2026-04",
61			})
62		}
63		return nil
64	}
65	
66	// emitCommand mirrors emitRule under .claude/commands/agent-sync. See
67	// emitRule's Rule-of-Three note before collapsing.
68	func emitCommand(emitted *emittedOps, node irNode, state *emitState) error {
69		body, err := decodeBodyOrPassthrough(node.Body)
70		if err != nil {
71			return wrapBodyErr(node, err)
72		}
73	
74		if err := ensureSubdir(emitted, commandsSubdir, state); err != nil {
75			return err
76		}
77	
78		cmdPath := commandsSubdir + "/" + node.ID + ".md"
79		if err := state.recordWritePath(cmdPath); err != nil {
80			return err
81		}
82		wf, err := adapterkit.NewOpWriteFile(cmdPath, 0o644, prependHeader(state, node, body))
83		if err != nil {
84			return wrapOpErr(node, err)
85		}
86		emitted.add(wf)
87		return nil
88	}
89	
90	// emitSkill maps one skill node to:
91	//   - mkdir(.claude/skills/agent-sync-<id>)
92	//   - write_file(.claude/skills/agent-sync-<id>/SKILL.md)
93	//   - write_file(.claude/skills/agent-sync-<id>/<asset.RelPath>) for each asset
94	//
95	// Asset RelPaths are validated to stay inside the skill's own folder.
96	// Without this check a malicious or buggy IR could escape into a
97	// sibling skill folder via `../agent-sync-victim/SKILL.md` — the runtime's
98	// declared-outputs gate accepts any cleaned path inside .claude/skills,
99	// so per-skill containment must be enforced here.
100	//
101	// Asset RelPaths are also rejected when they collide with the
102	// reserved SKILL.md filename or with another asset's path: such
103	// collisions would silently last-write-wins at the sync layer,
104	// reintroducing the same overwrite class rejectDuplicateNodes guards
105	// against at the node level.
106	//
107	// The skill folder gets no README.md: a per-skill README would clash
108	// with skill-discovery semantics, and the parent .claude/skills can
109	// hold user skills that we don't own.
110	func emitSkill(emitted *emittedOps, node irNode, state *emitState) error {
111		body, err := decodeBodyOrPassthrough(node.Body)
112		if err != nil {
113			return wrapBodyErr(node, err)
114		}
115	
116		skillDir := skillsParent + "/" + skillPrefix + node.ID
117		emitted.add(adapterkit.OpMkdir{Path: skillDir, Mode: 0o755})
118	
119		skillPath := skillDir + "/" + skillEntryFile
120		if err := state.recordWritePath(skillPath); err != nil {
121			return err
122		}
123		wf, err := adapterkit.NewOpWriteFile(skillPath, 0o644, skillFileContent(state, node, body))
124		if err != nil {
125			return wrapOpErr(node, err)
126		}
127		emitted.add(wf)
128	
129		// Warning-plus-emit (plan U5): a description-less canonical skill
130		// still emits (skillFileContent substitutes the deterministic
131		// fallback) — never warning-only, which would trip the runtime's
132		// capability-lie gate — but the gap is surfaced as a degraded
133		// warning so authors know their skill shows placeholder text in
134		// tool UIs. Mirrors the claude adapter's paths: rule warning.
135		if node.Description == "" {
136			emitted.add(adapterkit.OpWarning{
137				ConceptID: node.ID,
138				Status:    adapterkit.WarningStatusDegraded,
139				Note:      "skill has no description: frontmatter — emitted with a placeholder; author one in the canonical SKILL.md",
140			})
141		}
142	
143		assets := slices.Clone(node.Assets)
144		slices.SortFunc(assets, func(a, b irAsset) int { return cmp.Compare(a.RelPath, b.RelPath) })
145	
146		for _, a := range assets {
147			if err := validateAssetRelPath(node.ID, a.RelPath); err != nil {
148				return err
149			}
150			assetPath := skillDir + "/" + a.RelPath
151			if err := state.recordWritePath(assetPath); err != nil {
152				return &adapterkit.Error{
153					Code:    adapterkit.CodeInvalidParams,
154					Message: fmt.Sprintf("claude: skill %q asset %q collides with another emitted path", node.ID, a.RelPath),
155				}
156			}
157			assetBody, err := decodeBodyOrPassthrough(a.Content)
158			if err != nil {
159				return &adapterkit.Error{
160					Code:    adapterkit.CodeInvalidParams,
161					Message: fmt.Sprintf("claude: skill %q asset %q body: %s", node.ID, a.RelPath, err.Error()),
162				}
163			}
164			op, err := adapterkit.NewOpWriteFile(assetPath, 0o644, assetBody)
165			if err != nil {
166				return &adapterkit.Error{
167					Code:    adapterkit.CodeInvalidParams,
168					Message: fmt.Sprintf("claude: skill %q asset %q: %s", node.ID, a.RelPath, err.Error()),
169				}
170			}
171			emitted.add(op)
172		}
173		return nil
174	}
175	
176	// validateAssetRelPath rejects RelPath shapes that would let a skill
177	// asset escape its own folder, target a directory rather than a file,
178	// or collide with the reserved SKILL.md entrypoint. Defense in depth:
179	// the runtime's declared-outputs gate catches workspace escapes but
180	// does not enforce per-skill containment, so the adapter is the only
181	// line of defense for this class of issue.
182	func validateAssetRelPath(skillID, relPath string) error {
183		if relPath == "" {
184			return &adapterkit.Error{
185				Code:    adapterkit.CodeInvalidParams,
186				Message: fmt.Sprintf("claude: skill %q has asset with empty rel_path", skillID),
187			}
188		}
189		// Reject absolute paths (POSIX or Windows-volume) and backslash —
190		// wire-protocol paths are forward-slash only.
191		if strings.HasPrefix(relPath, "/") || strings.ContainsRune(relPath, '\\') {
192			return &adapterkit.Error{
193				Code:    adapterkit.CodeInvalidParams,
194				Message: fmt.Sprintf("claude: skill %q asset %q must be a forward-slash workspace-relative path", skillID, relPath),
195			}
196		}
197		// path.Clean normalizes "./", duplicate "//", and "..". If the
198		// cleaned form differs from the input, or starts with "..", or
199		// contains a "/.." segment, the path tries to escape the skill
200		// folder. Reject.
201		cleaned := path.Clean(relPath)
202		if cleaned == ".." || strings.HasPrefix(cleaned, "../") || strings.Contains(cleaned, "/../") {
203			return &adapterkit.Error{
204				Code:    adapterkit.CodeInvalidParams,
205				Message: fmt.Sprintf("claude: skill %q asset %q escapes skill folder via ..", skillID, relPath),
206			}
207		}
208		if cleaned != relPath {
209			return &adapterkit.Error{
210				Code:    adapterkit.CodeInvalidParams,
211				Message: fmt.Sprintf("claude: skill %q asset %q is not in canonical form (cleaned: %q)", skillID, relPath, cleaned),
212			}
213		}
214		// Reject directory-only paths. path.Clean(".") == "." which would
215		// produce an op path like ".claude/skills/agent-sync-x/." pointing at
216		// the skill directory itself, not a file. Reject before the sync
217		// engine has to handle it.
218		if cleaned == "." {
219			return &adapterkit.Error{
220				Code:    adapterkit.CodeInvalidParams,
221				Message: fmt.Sprintf("claude: skill %q asset rel_path must name a file, not the skill directory itself (got %q)", skillID, relPath),
222			}
223		}
224		// Reject the reserved SKILL.md entrypoint path. SKILL.md is owned
225		// by the skill body emission above; an asset sharing that name
226		// would silently overwrite the skill body itself.
227		if cleaned == skillEntryFile {
228			return &adapterkit.Error{
229				Code:    adapterkit.CodeInvalidParams,
230				Message: fmt.Sprintf("claude: skill %q asset rel_path %q collides with the reserved SKILL.md entrypoint", skillID, relPath),
231			}
232		}
233		return nil
234	}
235	
236	// ensureSubdir adds the per-emit mkdir + README pair for a reserved
237	// subdirectory once per emit call. Subsequent calls are no-ops.
238	//
239	// Returns InvalidParams if a node ID has already taken the README
240	// path inside this subdir (e.g., a rule node literally named "README"
241	// — its emitted path would be .../agent-sync/README.md).
242	func ensureSubdir(emitted *emittedOps, subdir string, state *emitState) error {
243		if state.readmeEmitted[subdir] {
244			return nil
245		}
246		state.readmeEmitted[subdir] = true
247		emitted.add(adapterkit.OpMkdir{Path: subdir, Mode: 0o755})
248		readmePath := subdir + "/README.md"
249		if err := state.recordWritePath(readmePath); err != nil {
250			return err
251		}
252		wf, err := adapterkit.NewOpWriteFile(readmePath, 0o644, readmeForSubdir(subdir))
253		if err != nil {
254			// readmeForSubdir returns a small fixed body; the only way
255			// NewOpWriteFile can fail is the payload-too-large guard,
256			// which is unreachable here. Panic surfaces the bug.
257			panic(fmt.Sprintf("claude: building README for %s: %v", subdir, err))
258		}
259		emitted.add(wf)
260		return nil
261	}
262	
263	// prependHeader inserts the managed-file header before the body. The
264	// header carries per-node provenance when the node has a source
265	// override (composed nodes); otherwise the session-level source.
266	func prependHeader(state *emitState, node irNode, body []byte) []byte {
267		header := renderManagedHeader(sourceForNode(state, node))
268		out := make([]byte, 0, len(header)+len(body))
269		out = append(out, header...)
270		out = append(out, body...)
271		return out
272	}
273	
274	// sourceForNode resolves the provenance identity for a node: the
275	// per-node override (composed nodes) when present, else the session.
276	func sourceForNode(state *emitState, node irNode) (url, commit string) {
277		if node.SourceURL != "" {
278			return node.SourceURL, node.SourceCommit
279		}
280		return state.sourceURL, state.sourceCommit
281	}
282	
283	// skillFileContent renders an emitted SKILL.md: YAML frontmatter at
284	// byte 0 (Claude Code and Agent Skills consumers parse it only there),
285	// the managed header below it, then the body. Unauthored descriptions
286	// get the deterministic skillmeta fallback; the degraded OpWarning (U5)
287	// makes the gap visible. Skills are the only header-second kind.
288	func skillFileContent(state *emitState, node irNode, body []byte) []byte {
289		url, commit := sourceForNode(state, node)
290		desc := node.Description
291		if desc == "" {
292			desc = skillmeta.FallbackDescription(url)
293		}
294		fm := skillmeta.Frontmatter(skillPrefix+node.ID, desc)
295		header := renderManagedHeader(url, commit)
296		out := make([]byte, 0, len(fm)+len(header)+len(body))
297		out = append(out, fm...)
298		out = append(out, header...)
299		out = append(out, body...)
300		return out
301	}
302	
303	// hasPathsFrontmatter reports whether body opens with a YAML
304	// frontmatter block whose first content line is `paths:`. Best-
305	// effort: a body with frontmatter that places `paths:` after other
306	// fields is missed. v1 ships the conservative check; full
307	// frontmatter exposure is a v1.x change to the IR.
308	//
309	// Accepts both `---\n` and `---\r\n` separators so Windows-authored
310	// rule files don't silently slip past the warning.
311	func hasPathsFrontmatter(body []byte) bool {
312		rest, ok := stripFrontmatterOpener(body)
313		if !ok {
314			return false
315		}
316		// Look at the first non-blank line of the YAML block; reject if
317		// the first key is anything other than `paths`.
318		for {
319			nl := bytes.IndexByte(rest, '\n')
320			if nl < 0 {
321				return false
322			}
323			line := rest[:nl]
324			trim := bytes.TrimSpace(line)
325			if len(trim) == 0 {
326				rest = rest[nl+1:]
327				continue
328			}
329			return bytes.HasPrefix(trim, []byte("paths:"))
330		}
331	}
332	
333	// stripFrontmatterOpener returns the body bytes after a leading
334	// `---\n` or `---\r\n` separator. Returns ok=false when no opener is
335	// present.
336	func stripFrontmatterOpener(body []byte) ([]byte, bool) {
337		if bytes.HasPrefix(body, []byte("---\n")) {
338			return body[len("---\n"):], true
339		}
340		if bytes.HasPrefix(body, []byte("---\r\n")) {
341			return body[len("---\r\n"):], true
342		}
343		return nil, false
344	}
