58	// records returns the OpRecord summary slice the v1 protocol carries in
59	// EmitResult.OpsPerformed.
60	func (e *emittedOps) records() []adapterkit.OpRecord {
61		out := make([]adapterkit.OpRecord, 0, len(e.ops))
62		for _, op := range e.ops {
63			out = append(out, adapterkit.OpRecord{Op: op.OpKind(), Path: op.OpPath()})
