73			raw, err := json.Marshal(op)
74			if err != nil {
75				return nil, fmt.Errorf("pi: marshal op %s %q: %w", op.OpKind(), op.OpPath(), err)
76			}
77			out = append(out, raw)
78		}
79		return out, nil
80	}
81	
82	// handleEmit is the OnEmit handler the bundled adapter registers.
83	func handleEmit(ctx context.Context, params adapterkit.EmitParams, scope, sourceURL, sourceCommit string) (adapterkit.EmitResult, error) {
84		doc, err := decodeIRDocument(params.IR)
85		if err != nil {
86			return adapterkit.EmitResult{}, &adapterkit.Error{
87				Code:    adapterkit.CodeInvalidParams,
88				Message: fmt.Sprintf("pi: %s", err.Error()),
89			}
90		}
91	
92		if err := rejectDuplicateNodes(doc.Nodes); err != nil {
93			return adapterkit.EmitResult{}, err
94		}
95	
96		emitted := &emittedOps{}
97		state := emitState{
98			sourceURL:       sourceURL,
99			sourceCommit:    sourceCommit,
100			emittedFilePath: map[string]struct{}{},
101			paths:           resolvePathSet(scope),
102		}
103	
104		// Deterministic order (sorted by kind, then id) so op output is stable.
105		slices.SortFunc(doc.Nodes, func(a, b irNode) int {
106			if c := cmp.Compare(a.Kind, b.Kind); c != 0 {
107				return c
108			}
109			return cmp.Compare(a.ID, b.ID)
110		})
111	
112		for _, node := range doc.Nodes {
113			if err := ctx.Err(); err != nil {
114				return adapterkit.EmitResult{}, &adapterkit.Error{
115					Code:    adapterkit.CodeInternalError,
116					Message: fmt.Sprintf("pi: emit cancelled: %s", err.Error()),
117				}
118			}
119			if !nodeTargetsPi(node) {
120				continue
121			}
122			if err := dispatchNode(emitted, node, &state); err != nil {
123				return adapterkit.EmitResult{}, err
124			}
125		}
126	
127		wire, err := emitted.wireOps()
128		if err != nil {
129			return adapterkit.EmitResult{}, &adapterkit.Error{
130				Code:    adapterkit.CodeInternalError,
131				Message: err.Error(),
132			}
133		}
134		return adapterkit.EmitResult{OpsPerformed: emitted.records(), Ops: wire}, nil
135	}
136	
137	// emitState carries per-emit dedup state and the scope-resolved paths.
138	// emittedFilePath records every workspace-relative path emitted as a write_file
139	// so the dispatcher fails closed instead of letting the sync engine
140	// last-write-wins. paths hold the scope-resolved tool-owned destinations (only
141	// agents-md is scope-dependent).
142	type emitState struct {
143		// sourceURL / sourceCommit are the session-level source identity from
144		// InitializeParams (audit-safe canonical URL or local path + resolved
145		// SHA), used to render the managed header. A node-level override
146		// (composed nodes) wins over these — see prependHeader.
147		sourceURL    string
148		sourceCommit string
149	
150		emittedFilePath map[string]struct{}
151		paths           pathSet
152	}
153	
154	// recordWritePath registers a write_file path in the per-emit dedup table.
155	func (s *emitState) recordWritePath(path string) error {
156		if _, exists := s.emittedFilePath[path]; exists {
157			return &adapterkit.Error{
158				Code:    adapterkit.CodeInvalidParams,
159				Message: fmt.Sprintf("pi: duplicate write_file path %q in single emit", path),
160			}
161		}
162		s.emittedFilePath[path] = struct{}{}
163		return nil
164	}
165	
166	// dispatchNode routes one IR node to its kind-specific emitter.
167	//
168	// Supported kinds (agents-md, skill) produce ops; unsupported kinds
169	// (mcp-server-entry, rule, command, plugin-reference) produce a degradation
170	// warning and emit no files. The capability matrix in capabilities.go is the
171	// authoritative source for which kinds are supported; this switch must stay in
172	// agreement with it. (command is planned — see capabilities.yaml.)
173	func dispatchNode(emitted *emittedOps, node irNode, state *emitState) error {
174		if !ir.IsValidID(node.ID) {
175			return &adapterkit.Error{
176				Code:    adapterkit.CodeInvalidParams,
177				Message: fmt.Sprintf("pi: invalid node id %q", node.ID),
178			}
179		}
180		switch ir.Kind(node.Kind) {
181		case ir.KindAgentsMD:
182			return emitAgentsMD(emitted, node, state)
183		case ir.KindSkill:
184			return emitSkill(emitted, node, state)
185		case ir.KindMCPServerEntry, ir.KindRule, ir.KindCommand, ir.KindPluginReference:
186			return emitUnsupportedWarning(emitted, node)
187		default:
188			return &adapterkit.Error{
189				Code:    adapterkit.CodeInvalidParams,
190				Message: fmt.Sprintf("pi: unknown IR kind %q for node %q", node.Kind, node.ID),
191			}
192		}
193	}
194	
195	// decodeIRDocument unmarshals the EmitParams.IR raw message.
196	func decodeIRDocument(raw json.RawMessage) (irDocument, error) {
197		if len(raw) == 0 {
198			return irDocument{}, nil
199		}
200		var doc irDocument
201		if err := json.Unmarshal(raw, &doc); err != nil {
202			return irDocument{}, fmt.Errorf("decode IR document: %w", err)
203		}
204		return doc, nil
205	}
206	
207	// nodeTargetsPi reports whether the node's targets list is empty (means "all
208	// adapters") or includes the pi adapter.
209	func nodeTargetsPi(node irNode) bool {
210		if len(node.Targets) == 0 {
211			return true
212		}
213		for _, t := range node.Targets {
214			if t == adapterName {
215				return true
216			}
217		}
218		return false
219	}
220	
221	// rejectDuplicateNodes returns InvalidParams when the wire payload contains two
222	// or more nodes with the same (kind, id) pair.
223	func rejectDuplicateNodes(nodes []irNode) error {
224		seen := make(map[string]struct{}, len(nodes))
225		for _, n := range nodes {
226			key := n.Kind + "/" + n.ID
227			if _, dup := seen[key]; dup {
228				return &adapterkit.Error{
229					Code:    adapterkit.CodeInvalidParams,
230					Message: fmt.Sprintf("pi: duplicate node (kind=%q id=%q) in IR payload", n.Kind, n.ID),
231				}
232			}
233			seen[key] = struct{}{}
234		}
235		return nil
236	}
237	
238	// decodeBodyOrPassthrough turns a node or asset Body field into raw bytes.
239	func decodeBodyOrPassthrough(raw json.RawMessage) ([]byte, error) {
240		if len(raw) == 0 || string(raw) == "null" {
241			return nil, nil
242		}
243		var s string
244		if err := json.Unmarshal(raw, &s); err == nil {
245			return []byte(s), nil
246		}
247		var any any
248		if err := json.Unmarshal(raw, &any); err != nil {
249			return nil, fmt.Errorf("body must be a JSON string or valid JSON value: %w", err)
250		}
251		return raw, nil
252	}
253	
254	// wrapBodyErr converts a node-body decode error into a structured JSON-RPC error.
255	func wrapBodyErr(node irNode, err error) error {
256		return &adapterkit.Error{
257			Code:    adapterkit.CodeInvalidParams,
258			Message: fmt.Sprintf("pi: node %q (%s) body: %s", node.ID, node.Kind, err.Error()),
259		}
260	}
261	
262	// wrapOpErr converts an op-construction error into a structured JSON-RPC error.
263	func wrapOpErr(node irNode, err error) error {
264		return &adapterkit.Error{
265			Code:    adapterkit.CodeInvalidParams,
266			Message: fmt.Sprintf("pi: node %q (%s) op: %s", node.ID, node.Kind, err.Error()),
267		}
268	}
