package pi

import (
	"cmp"
	"context"
	"encoding/json"
	"fmt"
	"slices"

	"github.com/agent-sync/agent-sync/internal/ir"
	"github.com/agent-sync/agent-sync/pkg/adapterkit"
)

// irNode is the wire-side shape of one IR node delivered via EmitParams.IR.
// Identical to the claude/cursor/codex adapters' irNode so the four share one
// auditable wire shape.
type irNode struct {
	ID       string   `json:"id"`
	Kind     string   `json:"kind"`
	Version  int      `json:"version,omitempty"`
	Required bool     `json:"required,omitempty"`
	Targets  []string `json:"targets,omitempty"`
	// Description, SourceURL, SourceCommit are additive wire fields (plan
	// U2): the authored frontmatter description and the per-node source
	// override for composed nodes (empty = inherit the session source).
	Description  string          `json:"description,omitempty"`
	SourceURL    string          `json:"source_url,omitempty"`
	SourceCommit string          `json:"source_commit,omitempty"`
	Provenance   irProvenance    `json:"provenance,omitempty"`
	Body         json.RawMessage `json:"body,omitempty"`
	Assets       []irAsset       `json:"assets,omitempty"`
}

type irProvenance struct {
	Path    string `json:"path,omitempty"`
	BlobSHA string `json:"blob_sha,omitempty"`
}

type irAsset struct {
	RelPath    string          `json:"rel_path"`
	Provenance irProvenance    `json:"provenance,omitempty"`
	Content    json.RawMessage `json:"content,omitempty"`
}

type irDocument struct {
	Nodes []irNode `json:"nodes"`
}

// emittedOps accumulates the ops a single emit call produces.
type emittedOps struct {
	ops []adapterkit.Op
}

func (e *emittedOps) add(op adapterkit.Op) {
	e.ops = append(e.ops, op)
}

// records returns the OpRecord summary slice the v1 protocol carries in
// EmitResult.OpsPerformed.
func (e *emittedOps) records() []adapterkit.OpRecord {
	out := make([]adapterkit.OpRecord, 0, len(e.ops))
	for _, op := range e.ops {
		out = append(out, adapterkit.OpRecord{Op: op.OpKind(), Path: op.OpPath()})
	}
	return out
}

// wireOps marshals each accumulated op to its wire envelope for
// EmitResult.Ops, carrying op content to the CLI core (invariant #2).
func (e *emittedOps) wireOps() ([]json.RawMessage, error) {
	out := make([]json.RawMessage, 0, len(e.ops))
	for _, op := range e.ops {
		raw, err := json.Marshal(op)
		if err != nil {
			return nil, fmt.Errorf("pi: marshal op %s %q: %w", op.OpKind(), op.OpPath(), err)
		}
		out = append(out, raw)
	}
	return out, nil
}

// handleEmit is the OnEmit handler the bundled adapter registers.
func handleEmit(ctx context.Context, params adapterkit.EmitParams, scope, sourceURL, sourceCommit string) (adapterkit.EmitResult, error) {
	doc, err := decodeIRDocument(params.IR)
	if err != nil {
		return adapterkit.EmitResult{}, &adapterkit.Error{
			Code:    adapterkit.CodeInvalidParams,
			Message: fmt.Sprintf("pi: %s", err.Error()),
		}
	}

	if err := rejectDuplicateNodes(doc.Nodes); err != nil {
		return adapterkit.EmitResult{}, err
	}

	emitted := &emittedOps{}
	state := emitState{
		sourceURL:       sourceURL,
		sourceCommit:    sourceCommit,
		emittedFilePath: map[string]struct{}{},
		paths:           resolvePathSet(scope),
	}

	// Deterministic order (sorted by kind, then id) so op output is stable.
	slices.SortFunc(doc.Nodes, func(a, b irNode) int {
		if c := cmp.Compare(a.Kind, b.Kind); c != 0 {
			return c
		}
		return cmp.Compare(a.ID, b.ID)
	})

	for _, node := range doc.Nodes {
		if err := ctx.Err(); err != nil {
			return adapterkit.EmitResult{}, &adapterkit.Error{
				Code:    adapterkit.CodeInternalError,
				Message: fmt.Sprintf("pi: emit cancelled: %s", err.Error()),
			}
		}
		if !nodeTargetsPi(node) {
			continue
		}
		if err := dispatchNode(emitted, node, &state); err != nil {
			return adapterkit.EmitResult{}, err
		}
	}

	wire, err := emitted.wireOps()
	if err != nil {
		return adapterkit.EmitResult{}, &adapterkit.Error{
			Code:    adapterkit.CodeInternalError,
			Message: err.Error(),
		}
	}
	return adapterkit.EmitResult{OpsPerformed: emitted.records(), Ops: wire}, nil
}

// emitState carries per-emit dedup state and the scope-resolved paths.
// emittedFilePath records every workspace-relative path emitted as a write_file
// so the dispatcher fails closed instead of letting the sync engine
// last-write-wins. paths hold the scope-resolved tool-owned destinations (only
// agents-md is scope-dependent).
type emitState struct {
	// sourceURL / sourceCommit are the session-level source identity from
	// InitializeParams (audit-safe canonical URL or local path + resolved
	// SHA), used to render the managed header. A node-level override
	// (composed nodes) wins over these — see prependHeader.
	sourceURL    string
	sourceCommit string

	emittedFilePath map[string]struct{}
	paths           pathSet
}

// recordWritePath registers a write_file path in the per-emit dedup table.
func (s *emitState) recordWritePath(path string) error {
	if _, exists := s.emittedFilePath[path]; exists {
		return &adapterkit.Error{
			Code:    adapterkit.CodeInvalidParams,
			Message: fmt.Sprintf("pi: duplicate write_file path %q in single emit", path),
		}
	}
	s.emittedFilePath[path] = struct{}{}
	return nil
}

// dispatchNode routes one IR node to its kind-specific emitter.
//
// Supported kinds (agents-md, skill) produce ops; unsupported kinds
// (mcp-server-entry, rule, command, plugin-reference) produce a degradation
// warning and emit no files. The capability matrix in capabilities.go is the
// authoritative source for which kinds are supported; this switch must stay in
// agreement with it. (command is planned — see capabilities.yaml.)
func dispatchNode(emitted *emittedOps, node irNode, state *emitState) error {
	if !ir.IsValidID(node.ID) {
		return &adapterkit.Error{
			Code:    adapterkit.CodeInvalidParams,
			Message: fmt.Sprintf("pi: invalid node id %q", node.ID),
		}
	}
	switch ir.Kind(node.Kind) {
	case ir.KindAgentsMD:
		return emitAgentsMD(emitted, node, state)
	case ir.KindSkill:
		return emitSkill(emitted, node, state)
	case ir.KindMCPServerEntry, ir.KindRule, ir.KindCommand, ir.KindPluginReference:
		return emitUnsupportedWarning(emitted, node)
	default:
		return &adapterkit.Error{
			Code:    adapterkit.CodeInvalidParams,
			Message: fmt.Sprintf("pi: unknown IR kind %q for node %q", node.Kind, node.ID),
		}
	}
}

// decodeIRDocument unmarshals the EmitParams.IR raw message.
func decodeIRDocument(raw json.RawMessage) (irDocument, error) {
	if len(raw) == 0 {
		return irDocument{}, nil
	}
	var doc irDocument
	if err := json.Unmarshal(raw, &doc); err != nil {
		return irDocument{}, fmt.Errorf("decode IR document: %w", err)
	}
	return doc, nil
}

// nodeTargetsPi reports whether the node's targets list is empty (means "all
// adapters") or includes the pi adapter.
func nodeTargetsPi(node irNode) bool {
	if len(node.Targets) == 0 {
		return true
	}
	for _, t := range node.Targets {
		if t == adapterName {
			return true
		}
	}
	return false
}

// rejectDuplicateNodes returns InvalidParams when the wire payload contains two
// or more nodes with the same (kind, id) pair.
func rejectDuplicateNodes(nodes []irNode) error {
	seen := make(map[string]struct{}, len(nodes))
	for _, n := range nodes {
		key := n.Kind + "/" + n.ID
		if _, dup := seen[key]; dup {
			return &adapterkit.Error{
				Code:    adapterkit.CodeInvalidParams,
				Message: fmt.Sprintf("pi: duplicate node (kind=%q id=%q) in IR payload", n.Kind, n.ID),
			}
		}
		seen[key] = struct{}{}
	}
	return nil
}

// decodeBodyOrPassthrough turns a node or asset Body field into raw bytes.
func decodeBodyOrPassthrough(raw json.RawMessage) ([]byte, error) {
	if len(raw) == 0 || string(raw) == "null" {
		return nil, nil
	}
	var s string
	if err := json.Unmarshal(raw, &s); err == nil {
		return []byte(s), nil
	}
	var any any
	if err := json.Unmarshal(raw, &any); err != nil {
		return nil, fmt.Errorf("body must be a JSON string or valid JSON value: %w", err)
	}
	return raw, nil
}

// wrapBodyErr converts a node-body decode error into a structured JSON-RPC error.
func wrapBodyErr(node irNode, err error) error {
	return &adapterkit.Error{
		Code:    adapterkit.CodeInvalidParams,
		Message: fmt.Sprintf("pi: node %q (%s) body: %s", node.ID, node.Kind, err.Error()),
	}
}

// wrapOpErr converts an op-construction error into a structured JSON-RPC error.
func wrapOpErr(node irNode, err error) error {
	return &adapterkit.Error{
		Code:    adapterkit.CodeInvalidParams,
		Message: fmt.Sprintf("pi: node %q (%s) op: %s", node.ID, node.Kind, err.Error()),
	}
}

package pi

import (
	"bytes"
	"fmt"

	"github.com/agent-sync/agent-sync/pkg/adapterkit"
)

const (
	agentsMDPath    = "AGENTS.md"
	sectionIDPrefix = "agent-sync:"

	// scopeUser is the wire value (hierarchy.Level.String()) for the user-home
	// scope. Any other value (incl. "" / "project" / "directory") is project
	// scope.
	scopeUser = "user"

	// userAgentsMDPath is where Pi reads user-global agent instructions:
	// ~/.pi/agent/AGENTS.md (the scope root is $HOME at user scope). Pi does NOT
	// read ~/AGENTS.md at the user level, so this is a genuine remap — the same
	// shape as Codex's AGENTS.md → ~/.codex/AGENTS.md. The global config base is
	// ~/.pi/agent/ (verified 2026-06-30), and can be relocated via
	// PI_CODING_AGENT_DIR (documented assumption; not handled). See plan
	// docs/plans/2026-06-30-002.
	userAgentsMDPath = ".pi/agent/AGENTS.md"
)

// pathSet holds the scope-resolved destination for the agents-md overlay. The
// skills tree (.agents/skills/) is unconditional: its relative path already
// resolves correctly under $HOME at user scope (Pi reads ~/.agents/skills/), so
// only agents-md needs scope-dependent resolution.
type pathSet struct {
	agentsMD string
}

// resolvePathSet maps the initialize scope to Pi's scope-dependent paths.
// declaredOutputs (capabilities.go) and the emitted op paths (here) MUST both
// resolve from this one function so they never drift — a mismatch is rejected
// by the runtime's path-safety gate.
func resolvePathSet(scope string) pathSet {
	if scope == scopeUser {
		return pathSet{agentsMD: userAgentsMDPath}
	}
	return pathSet{agentsMD: agentsMDPath}
}

// markerOpenBytes is the literal HTML-comment opener every agent-sync section
// marker uses. An agents-md body containing this sequence is rejected so a
// hostile body can't forge a section split inside AGENTS.md.
var markerOpenBytes = []byte("<!-- agent-sync:")

// emitAgentsMD writes the agents-md node into AGENTS.md (workspace root at
// project scope; .pi/agent/AGENTS.md at user scope) as a managed section
// between <!-- agent-sync:begin id=<id> --> and <!-- agent-sync:end id=<id> -->
// markers. AGENTS.md is tool-owned (read by Pi and other agents); user content
// outside the managed section is preserved by the merge step.
//
// pi, codex, and cursor all section-merge into the same AGENTS.md, each keyed
// by its node id; the marker syntax is byte-identical so the sections coexist.
//
// The body is rejected when it contains the agent-sync marker opener: a body
// carrying `<!-- agent-sync:end id=other -->` could forge another section,
// leaving the merged AGENTS.md with conflicting markers the merge cannot
// resolve safely.
func emitAgentsMD(emitted *emittedOps, node irNode, state *emitState) error {
	body, err := decodeBodyOrPassthrough(node.Body)
	if err != nil {
		return wrapBodyErr(node, err)
	}
	if bytes.Contains(body, markerOpenBytes) {
		return &adapterkit.Error{
			Code:    adapterkit.CodeInvalidParams,
			Message: fmt.Sprintf("pi: agents-md %q body contains agent-sync marker syntax (%q); refusing to corrupt %s", node.ID, string(markerOpenBytes), state.paths.agentsMD),
		}
	}
	// The engine owns the begin/end markers (it renders the managed block from
	// the locator during the markdown-section merge). The adapter passes the
	// INNER body only — sending marker-wrapped content is rejected by the merge.
	emitted.add(adapterkit.OpWriteToolOwned{
		Path:    state.paths.agentsMD,
		Kind:    adapterkit.ToolOwnedKindMarkdownSection,
		Locator: sectionIDPrefix + node.ID,
		Content: body,
	})
	return nil
}

package pi

import (
	"fmt"

	"github.com/agent-sync/agent-sync/internal/ir"
	"github.com/agent-sync/agent-sync/pkg/adapterkit"
)

// unsupportedNotes maps each unsupported IR kind to its user-facing degradation
// note. Pi reads none of these at the project level; the adapter declines
// honestly rather than emitting dead files into directories Pi never reads.
//
// mcp-server-entry and rule are deliberate Pi product exclusions; command is
// planned but not yet emitted (see capabilities.yaml); plugin-reference has no
// project-level file shape in Pi.
var unsupportedNotes = map[ir.Kind]string{
	ir.KindMCPServerEntry:  "Pi does not load MCP servers by design — see https://mariozechner.at/posts/2025-11-02-what-if-you-dont-need-mcp/. The MCP entry was not installed. To expose this capability to Pi, build or install a Pi extension that wraps it.",
	ir.KindRule:            "Pi has no per-tool rule concept distinct from AGENTS.md; the rule was not installed. Consolidate rule content into an agents-md node or a skill.",
	ir.KindCommand:         "The agent-sync pi adapter does not emit prompt-template commands yet (planned); the command was not installed. Pi itself supports prompt templates at .pi/prompts/.",
	ir.KindPluginReference: "Pi packages install via `pi install` (npm/git), not a project-level plugin-reference registry; the reference was not installed.",
}

// emitUnsupportedWarning surfaces the unsupported declaration for a node whose
// kind pi does not emit. No write_file is emitted.
//
// The runtime's capability-lied check only fires for kinds the adapter declared
// as `supported`, so emitting a warning-only result here is safe — all four
// kinds routed here are declared `unsupported` in capabilities.yaml. See
// internal/adapter/runtime.go and the capability-lie-gate memory.
func emitUnsupportedWarning(emitted *emittedOps, node irNode) error {
	note, ok := unsupportedNotes[ir.Kind(node.Kind)]
	if !ok {
		return &adapterkit.Error{
			Code:    adapterkit.CodeInternalError,
			Message: fmt.Sprintf("pi: no unsupported-note for kind %q (node %q)", node.Kind, node.ID),
		}
	}
	emitted.add(adapterkit.OpWarning{
		ConceptID: node.ID,
		Status:    adapterkit.WarningStatusDegraded,
		Note:      note,
	})
	return nil
}

package pi

// managedHeaderTemplate is the canonical "do not edit" banner the pi adapter
// prepends to every owned markdown file (skills). The {source-url} and
// {short-sha} placeholders are filled in by the sync engine once it plumbs
// IR-decode context through EmitParams._meta. It is byte-identical to the codex
// adapter's header, so a skill co-emitted to the shared .agents/skills/ tree by
// both adapters produces the same SKILL.md bytes.
//
// renderManagedHeader renders the "do not edit" banner with real
// provenance (plan U3). sourceURL is the audit-safe source identity —
// the cache-canonicalized git URL or a local source path — from the
// session, or a per-node override for composed nodes. sourceCommit is
// the resolved canonical SHA, empty for working-tree sources. Forms:
//
//	git-backed: <!-- … Source: <url>@<sha12>. Regenerate: … -->
//	local:      <!-- … Source: <path>. Regenerate: … -->
//	no source:  <!-- … Regenerate: … --> (defensive; a session from a
//	            pre-U2 engine carries no source identity)
//
// The trailing blank line keeps a one-line gap between the header and
// user-visible content. BYTE-IDENTITY: codex and pi must render the
// exact same bytes for the same inputs — the shared .agents/skills
// tree is co-emitted (ADV-1) and the engine fail-closes on divergence.
func renderManagedHeader(sourceURL, sourceCommit string) []byte {
	const pre = "<!-- Managed by agent-sync — do not edit. "
	const post = "Regenerate: agent-sync sync -->\n\n"
	switch {
	case sourceURL == "":
		return []byte(pre + post)
	case sourceCommit == "":
		return []byte(pre + "Source: " + sourceURL + ". " + post)
	default:
		return []byte(pre + "Source: " + sourceURL + "@" + shortSHA(sourceCommit) + ". " + post)
	}
}

// shortSHA truncates a full commit SHA to git's collision-safe 12-char
// display form; shorter inputs pass through unchanged.
func shortSHA(sha string) string {
	if len(sha) > 12 {
		return sha[:12]
	}
	return sha
}

