// "all adapters") or includes the antigravity adapter.
func nodeTargetsAntigravity(node irNode) bool {
	if len(node.Targets) == 0 {
		return true
	}
	for _, t := range node.Targets {
		if t == adapterName {
			return true
		}
	}
