16	// captureOps replicates handleEmit's flow (sort + dedup + dispatch) at project
17	// scope but returns the raw emittedOps so tests can inspect op-specific fields.
18	func captureOps(raw json.RawMessage) (*emittedOps, error) {
19		return captureOpsScope(raw, "project")
20	}
21	
22	func captureOpsScope(raw json.RawMessage, scope string) (*emittedOps, error) {
23		doc, err := decodeIRDocument(raw)
24		if err != nil {
25			return nil, err
26		}
27		if err := rejectDuplicateNodes(doc.Nodes); err != nil {
28			return nil, err
29		}
30		emitted := &emittedOps{}
31		state := &emitState{
32			readmeEmitted:   map[string]bool{},
33			emittedFilePath: map[string]struct{}{},
34			paths:           resolvePathSet(scope),
35		}
36		sort.Slice(doc.Nodes, func(i, j int) bool {
37			if doc.Nodes[i].Kind != doc.Nodes[j].Kind {
38				return doc.Nodes[i].Kind < doc.Nodes[j].Kind
39			}
40			return doc.Nodes[i].ID < doc.Nodes[j].ID
41		})
42		for _, n := range doc.Nodes {
43			if !nodeTargetsAntigravity(n) {
44				continue
45			}
46			if err := dispatchNode(emitted, n, state); err != nil {
47				return nil, err
48			}
49		}
50		return emitted, nil
51	}
