120	
121	// ownedSubdirs returns the declared-output paths whose mode is
122	// owned-subdir, sorted longest-first so the most specific prefix wins
123	// when paths nest.
124	func ownedSubdirs(outputs []contract.DeclaredOutput) []string {
125		var owned []string
126		for _, o := range outputs {
127			if o.Mode == contract.OutputModeOwnedSubdir {
128				owned = append(owned, o.Path)
129			}
130		}
131		sort.Slice(owned, func(i, j int) bool { return len(owned[i]) > len(owned[j]) })
132		return owned
133	}
134	
135	// ownerOf returns the owned-subdir prefix that contains p, or "" if none.
136	func ownerOf(owned []string, p string) string {
137		for _, pre := range owned {
138			if p == pre || strings.HasPrefix(p, pre+"/") {
139				return pre
140			}
141		}
142		return ""
143	}
144	
145	// sharedSubdirs returns the declared-output paths whose mode is shared-subdir.
146	// These are directories agent-sync shares with the user and other tools; the
147	// engine never swaps the shared parent itself, only the agent-sync-owned leaf
148	// entries within it (see effectiveOwnedPrefixes).
149	func sharedSubdirs(outputs []contract.DeclaredOutput) []string {
150		var shared []string
151		for _, o := range outputs {
152			if o.Mode == contract.OutputModeSharedSubdir {
153				shared = append(shared, o.Path)
154			}
155		}
156		// Longest-first so leafUnder's linear scan picks the most-specific prefix
157		// when shared prefixes nest — same invariant ownedSubdirs relies on.
158		sort.Slice(shared, func(i, j int) bool { return len(shared[i]) > len(shared[j]) })
159		return shared
160	}
161	
162	// leafUnder returns the agent-sync-managed leaf directory of p within one of
163	// the shared prefixes — i.e. "<shared>/<firstSegment>" — or "" when p is not
164	// under any shared prefix. The leaf (not the shared parent) is the swap unit
165	// for shared-subdir outputs, so foreign sibling leaves are never touched.
166	func leafUnder(shared []string, p string) string {
167		for _, sp := range shared {
168			if !strings.HasPrefix(p, sp+"/") {
169				continue
170			}
171			rest := strings.TrimPrefix(p, sp+"/")
172			if i := strings.IndexByte(rest, '/'); i >= 0 {
173				rest = rest[:i] // first path segment below the shared parent
174			}
175			// A managed leaf must be a real child-dir name. Reject empty / dot /
176			// parent segments — defense-in-depth; the runtime declared-outputs gate
177			// already path.Cleans and rejects traversal before ops reach here.
178			if rest == "" || rest == "." || rest == ".." {
179				return ""
180			}
181			return sp + "/" + rest
182		}
183		return ""
184	}
185	
186	// effectiveOwnedPrefixes is the set of prefixes the engine treats as owned for
187	// stage+swap, drift, and orphan purposes: every owned-subdir prefix, plus — for
188	// each shared-subdir — only the agent-sync-managed leaf directories within it,
189	// derived from this run's emitted ops and the prior ledger. The shared parent
190	// is deliberately absent, so it is never swapped wholesale and foreign sibling
191	// leaves (never emitted, never in the ledger) are invisible to the engine.
