1	package cursor
2	
3	import (
4		"cmp"
5		"context"
6		"encoding/json"
7		"fmt"
8		"slices"
9	
10		"github.com/agent-sync/agent-sync/internal/ir"
11		"github.com/agent-sync/agent-sync/pkg/adapterkit"
12	)
13	
14	// irNode is the wire-side shape of one IR node delivered via
15	// EmitParams.IR. The adapter does not import internal/ir's Node
16	// directly because that type carries decoder-internal fields the
17	// wire payload doesn't include.
18	//
19	// The full wire shape (including Assets/Provenance) is retained even
20	// though cursor never reads Assets — skill is unsupported here and
21	// routed to a warning before assets would matter. Keeping the struct
22	// identical to the wire contract (and to the claude adapter's irNode)
23	// means an unknown future kind that does carry assets still decodes
24	// cleanly, and the two adapters share one auditable wire shape rather
25	// than drifting apart. These fields are intentional parity, not copy
26	// residue.
27	type irNode struct {
28		ID       string   `json:"id"`
29		Kind     string   `json:"kind"`
30		Version  int      `json:"version,omitempty"`
31		Required bool     `json:"required,omitempty"`
32		Targets  []string `json:"targets,omitempty"`
33		// Description, SourceURL, SourceCommit are additive wire fields (plan
34		// U2): the authored frontmatter description and the per-node source
35		// override for composed nodes (empty = inherit the session source).
36		Description  string          `json:"description,omitempty"`
37		SourceURL    string          `json:"source_url,omitempty"`
38		SourceCommit string          `json:"source_commit,omitempty"`
39		Provenance   irProvenance    `json:"provenance,omitempty"`
40		Body         json.RawMessage `json:"body,omitempty"`
41		Assets       []irAsset       `json:"assets,omitempty"`
42	}
43	
44	type irProvenance struct {
45		Path    string `json:"path,omitempty"`
46		BlobSHA string `json:"blob_sha,omitempty"`
47	}
48	
49	type irAsset struct {
50		RelPath    string          `json:"rel_path"`
51		Provenance irProvenance    `json:"provenance,omitempty"`
52		Content    json.RawMessage `json:"content,omitempty"`
53	}
54	
55	type irDocument struct {
56		Nodes []irNode `json:"nodes"`
57	}
58	
59	// emittedOps accumulates the ops a single emit call produces. Built
60	// up across kind-specific helpers; rendered into OpsPerformed at the
61	// end of handleEmit.
62	type emittedOps struct {
63		ops []adapterkit.Op
64	}
65	
66	func (e *emittedOps) add(op adapterkit.Op) {
67		e.ops = append(e.ops, op)
68	}
69	
70	// records returns the OpRecord summary slice the v1 protocol carries
71	// in EmitResult.OpsPerformed — the {kind, path} pairs the runtime's
72	// declared-outputs and capability-lied gates run against.
73	func (e *emittedOps) records() []adapterkit.OpRecord {
74		out := make([]adapterkit.OpRecord, 0, len(e.ops))
75		for _, op := range e.ops {
76			out = append(out, adapterkit.OpRecord{Op: op.OpKind(), Path: op.OpPath()})
77		}
78		return out
79	}
80	
81	// wireOps marshals each accumulated op to its wire envelope for
82	// EmitResult.Ops, in the same order as records(). This carries the op
83	// content to the CLI core, which performs the actual writes
84	// (invariant #2). Decoded caller-side via contract.DecodeOp.
85	func (e *emittedOps) wireOps() ([]json.RawMessage, error) {
86		out := make([]json.RawMessage, 0, len(e.ops))
87		for _, op := range e.ops {
88			raw, err := json.Marshal(op)
89			if err != nil {
90				return nil, fmt.Errorf("cursor: marshal op %s %q: %w", op.OpKind(), op.OpPath(), err)
91			}
92			out = append(out, raw)
93		}
94		return out, nil
95	}
96	
97	// handleEmit is the OnEmit handler the bundled adapter registers.
98	// Decodes the IR document, dispatches each node by kind, and returns
99	// the accumulated OpRecord summary.
100	//
101	// One-failed-node-fails-the-emit is the v1 behavior: if any node
102	// produces an error, the whole call returns that error and partially
103	// emitted ops are discarded. Per-node skip-with-warning is a Unit 8b
104	// extension.
105	//
106	// Context is checked between nodes so a runtime cancel during a
107	// large IR is honored without waiting for the full iteration.
108	func handleEmit(ctx context.Context, params adapterkit.EmitParams, scope, sourceURL, sourceCommit string) (adapterkit.EmitResult, error) {
109		doc, err := decodeIRDocument(params.IR)
110		if err != nil {
111			return adapterkit.EmitResult{}, &adapterkit.Error{
112				Code:    adapterkit.CodeInvalidParams,
113				Message: fmt.Sprintf("cursor: %s", err.Error()),
114			}
115		}
116	
117		// Detect duplicate (kind, id) pairs in the wire payload before
118		// emitting. The IR decoder enforces uniqueness on its own output
119		// but the wire shape can carry duplicates from a buggy or
120		// adversarial producer; emitting the same path twice would let
121		// the sync engine silently last-write-wins.
122		if err := rejectDuplicateNodes(doc.Nodes); err != nil {
123			return adapterkit.EmitResult{}, err
124		}
125	
126		emitted := &emittedOps{}
127	
128		// readmeEmitted dedups per-subdir mkdir+README pairs.
129		// sidecarEmitted dedups the .agent-sync-managed sidecar (only ever
130		// written next to .cursor/mcp.json; one per emit regardless of how
131		// many mcp-server-entry nodes are present).
132		state := emitState{
133			sourceURL:       sourceURL,
134			sourceCommit:    sourceCommit,
135			readmeEmitted:   map[string]bool{},
136			sidecarEmitted:  false,
137			emittedFilePath: map[string]struct{}{},
138			paths:           resolvePathSet(scope),
139			atUserScope:     scope == scopeUser,
140		}
141	
142		// Iterate in a deterministic order (sorted by kind, then id) so
143		// op output is stable across runs and easy to compare against
144		// fixtures. The IR decoder upstream already sorts the same way,
145		// but we re-sort defensively in case a malformed decoder ships
146		// nodes in arbitrary order.
147		slices.SortFunc(doc.Nodes, func(a, b irNode) int {
148			if c := cmp.Compare(a.Kind, b.Kind); c != 0 {
149				return c
150			}
151			return cmp.Compare(a.ID, b.ID)
152		})
153	
154		for _, node := range doc.Nodes {
155			if err := ctx.Err(); err != nil {
156				return adapterkit.EmitResult{}, &adapterkit.Error{
157					Code:    adapterkit.CodeInternalError,
158					Message: fmt.Sprintf("cursor: emit cancelled: %s", err.Error()),
159				}
160			}
161			if !nodeTargetsCursor(node) {
162				// Node is targeted at a different adapter — silent skip.
163				continue
164			}
165			if err := dispatchNode(emitted, node, &state); err != nil {
166				return adapterkit.EmitResult{}, err
167			}
168		}
169	
170		wire, err := emitted.wireOps()
171		if err != nil {
172			return adapterkit.EmitResult{}, &adapterkit.Error{
173				Code:    adapterkit.CodeInternalError,
174				Message: err.Error(),
175			}
176		}
177		return adapterkit.EmitResult{OpsPerformed: emitted.records(), Ops: wire}, nil
178	}
179	
180	// emitState carries per-emit dedup tables. Threading one struct
181	// instead of multiple maps keeps dispatchNode's signature stable as
182	// new dedup keys appear.
183	//
184	// emittedFilePath records every workspace-relative path that's been
185	// emitted as a write_file in this call. When two ops would target
186	// the same path the dispatcher fails closed instead of letting the
187	// sync engine last-write-wins.
188	type emitState struct {
189		// sourceURL / sourceCommit are the session-level source identity from
190		// InitializeParams (audit-safe canonical URL or local path + resolved
191		// SHA), used to render the managed header. A node-level override
192		// (composed nodes) wins over these — see prependHeader.
193		sourceURL    string
194		sourceCommit string
195	
196		readmeEmitted   map[string]bool
197		sidecarEmitted  bool
198		emittedFilePath map[string]struct{}
199		// paths are the scope-resolved tool-owned destinations (.cursor/mcp.json +
200		// sidecar at project scope; sidecar suppressed at user scope). Resolved once
201		// per emit from the initialize scope.
202		paths pathSet
203		// atUserScope is true when the initialize scope is the user-home scope.
204		// rule and agents-md have no file-addressable user-global home in Cursor, so
205		// dispatchNode skips them at user scope (internal/coverage emits the
206		// user-facing warning). See plan docs/plans/2026-06-30-001.
207		atUserScope bool
208	}
209	
210	// recordWritePath registers a write_file path in the per-emit dedup
211	// table. Returns an InvalidParams error when the path was already
212	// emitted earlier in this call. Callers should check before
213	// constructing the OpWriteFile so the error message can include
214	// node-level context.
215	func (s *emitState) recordWritePath(path string) error {
216		if _, exists := s.emittedFilePath[path]; exists {
217			return &adapterkit.Error{
218				Code:    adapterkit.CodeInvalidParams,
219				Message: fmt.Sprintf("cursor: duplicate write_file path %q in single emit", path),
220			}
221		}
222		s.emittedFilePath[path] = struct{}{}
223		return nil
224	}
225	
226	// dispatchNode routes one IR node to its kind-specific emitter.
227	//
228	// Supported kinds (rule, mcp-server-entry, agents-md) produce ops;
229	// unsupported kinds (skill, command, plugin-reference) produce a
230	// degradation warning and emit no files. The capability matrix in
231	// capabilities.go is the authoritative source for which kinds are
232	// supported; this switch must stay in agreement with it.
233	//
234	// At user scope, rule and agents-md are skipped (no op): Cursor has no
235	// file-addressable user-global home for either (User Rules live in app
236	// settings / cloud; there is no global AGENTS.md), so writing them under
237	// ~/.cursor/ or ~/AGENTS.md would be inert. internal/coverage emits the
238	// user-facing warning for these (computed from the manifest), so the adapter
239	// stays silent here to avoid a double warning.
240	//
241	// The silent skip is only safe because capabilitiesForWire declares rule and
242	// agents-md UNSUPPORTED at user scope: the runtime's capability-lied gate fails
243	// any session that declares a kind supported but emits zero non-warning ops for
244	// an in-target node of that kind. A user-scope manifest with only a rule (no
245	// MCP entry) is exactly that case — the unsupported declaration keeps it an
246	// honest no-op instead of a sync failure. See capabilitiesForWire and plan
247	// docs/plans/2026-06-30-001.
248	func dispatchNode(emitted *emittedOps, node irNode, state *emitState) error {
249		if !ir.IsValidID(node.ID) {
250			return &adapterkit.Error{
251				Code:    adapterkit.CodeInvalidParams,
252				Message: fmt.Sprintf("cursor: invalid node id %q", node.ID),
253			}
254		}
255		switch ir.Kind(node.Kind) {
256		case ir.KindRule:
257			if state.atUserScope {
258				return nil // no user-global rules home; see coverage.nonNativeAtUser
259			}
260			return emitRule(emitted, node, state)
261		case ir.KindMCPServerEntry:
262			return emitMCPServerEntry(emitted, node, state)
263		case ir.KindAgentsMD:
264			if state.atUserScope {
265				return nil // no user-global AGENTS.md home; see coverage.nonNativeAtUser
266			}
267			return emitAgentsMD(emitted, node)
268		case ir.KindSkill, ir.KindCommand, ir.KindPluginReference:
269			return emitUnsupportedWarning(emitted, node)
270		default:
271			return &adapterkit.Error{
272				Code:    adapterkit.CodeInvalidParams,
273				Message: fmt.Sprintf("cursor: unknown IR kind %q for node %q", node.Kind, node.ID),
274			}
275		}
276	}
277	
278	// decodeIRDocument unmarshals the EmitParams.IR raw message. Returns
279	// a wrapped error on parse failure so handleEmit can convert it to a
280	// JSON-RPC InvalidParams response.
281	func decodeIRDocument(raw json.RawMessage) (irDocument, error) {
282		if len(raw) == 0 {
283			return irDocument{}, nil
284		}
285		var doc irDocument
286		if err := json.Unmarshal(raw, &doc); err != nil {
287			return irDocument{}, fmt.Errorf("decode IR document: %w", err)
288		}
289		return doc, nil
290	}
291	
292	// nodeTargetsCursor reports whether the node's targets list either
293	// is empty (means "all adapters") or includes the cursor adapter.
294	// IR-side validation guarantees the contained values are known
295	// adapter names; we don't re-validate here.
296	func nodeTargetsCursor(node irNode) bool {
297		if len(node.Targets) == 0 {
298			return true
299		}
300		for _, t := range node.Targets {
301			if t == adapterName {
302				return true
303			}
304		}
305		return false
306	}
307	
308	// rejectDuplicateNodes returns InvalidParams when the wire payload
309	// contains two or more nodes with the same (kind, id) pair. The
310	// fail-closed default avoids the silent last-write-wins behavior the
311	// sync engine would otherwise hit at write time.
312	func rejectDuplicateNodes(nodes []irNode) error {
313		seen := make(map[string]struct{}, len(nodes))
314		for _, n := range nodes {
315			key := n.Kind + "/" + n.ID
316			if _, dup := seen[key]; dup {
317				return &adapterkit.Error{
318					Code:    adapterkit.CodeInvalidParams,
319					Message: fmt.Sprintf("cursor: duplicate node (kind=%q id=%q) in IR payload", n.Kind, n.ID),
320				}
321			}
322			seen[key] = struct{}{}
323		}
324		return nil
325	}
326	
327	// decodeBodyOrPassthrough turns a node or asset Body field into raw
328	// bytes. The wire shape allows two body encodings:
329	//   - JSON string (markdown bodies): `"# heading\n..."`
330	//   - Raw JSON value (json/toml kinds): `{"command":"node",...}`
331	//
332	// String-decode is tried first; if that fails the raw JSON value is
333	// validated and passed through unchanged.
334	func decodeBodyOrPassthrough(raw json.RawMessage) ([]byte, error) {
335		if len(raw) == 0 || string(raw) == "null" {
336			return nil, nil
337		}
338		var s string
339		if err := json.Unmarshal(raw, &s); err == nil {
340			return []byte(s), nil
341		}
342		var any any
343		if err := json.Unmarshal(raw, &any); err != nil {
344			return nil, fmt.Errorf("body must be a JSON string or valid JSON value: %w", err)
345		}
346		return raw, nil
347	}
348	
349	// wrapBodyErr converts a node-body decode error into the structured
350	// JSON-RPC error the caller returns.
351	func wrapBodyErr(node irNode, err error) error {
352		return &adapterkit.Error{
353			Code:    adapterkit.CodeInvalidParams,
354			Message: fmt.Sprintf("cursor: node %q (%s) body: %s", node.ID, node.Kind, err.Error()),
355		}
356	}
357	
358	// wrapOpErr converts an op-construction error (typically the
359	// payload-too-large guard inside NewOpWriteFile) into the structured
360	// JSON-RPC error the caller returns.
361	func wrapOpErr(node irNode, err error) error {
362		return &adapterkit.Error{
363			Code:    adapterkit.CodeInvalidParams,
364			Message: fmt.Sprintf("cursor: node %q (%s) op: %s", node.ID, node.Kind, err.Error()),
365		}
366	}
367

