package cursor

import (
	"cmp"
	"context"
	"encoding/json"
	"fmt"
	"slices"

	"github.com/agent-sync/agent-sync/internal/ir"
	"github.com/agent-sync/agent-sync/pkg/adapterkit"
)

// irNode is the wire-side shape of one IR node delivered via
// EmitParams.IR. The adapter does not import internal/ir's Node
// directly because that type carries decoder-internal fields the
// wire payload doesn't include.
//
// The full wire shape (including Assets/Provenance) is retained even
// though cursor never reads Assets — skill is unsupported here and
// routed to a warning before assets would matter. Keeping the struct
// identical to the wire contract (and to the claude adapter's irNode)
// means an unknown future kind that does carry assets still decodes
// cleanly, and the two adapters share one auditable wire shape rather
// than drifting apart. These fields are intentional parity, not copy
// residue.
type irNode struct {
	ID       string   `json:"id"`
	Kind     string   `json:"kind"`
	Version  int      `json:"version,omitempty"`
	Required bool     `json:"required,omitempty"`
	Targets  []string `json:"targets,omitempty"`
	// Description, SourceURL, SourceCommit are additive wire fields (plan
	// U2): the authored frontmatter description and the per-node source
	// override for composed nodes (empty = inherit the session source).
	Description  string          `json:"description,omitempty"`
	SourceURL    string          `json:"source_url,omitempty"`
	SourceCommit string          `json:"source_commit,omitempty"`
	Provenance   irProvenance    `json:"provenance,omitempty"`
	Body         json.RawMessage `json:"body,omitempty"`
	Assets       []irAsset       `json:"assets,omitempty"`
}

type irProvenance struct {
	Path    string `json:"path,omitempty"`
	BlobSHA string `json:"blob_sha,omitempty"`
}

type irAsset struct {
	RelPath    string          `json:"rel_path"`
	Provenance irProvenance    `json:"provenance,omitempty"`
	Content    json.RawMessage `json:"content,omitempty"`
}

type irDocument struct {
	Nodes []irNode `json:"nodes"`
}

// emittedOps accumulates the ops a single emit call produces. Built
// up across kind-specific helpers; rendered into OpsPerformed at the
// end of handleEmit.
type emittedOps struct {
	ops []adapterkit.Op
}

func (e *emittedOps) add(op adapterkit.Op) {
	e.ops = append(e.ops, op)
}

// records returns the OpRecord summary slice the v1 protocol carries
// in EmitResult.OpsPerformed — the {kind, path} pairs the runtime's
// declared-outputs and capability-lied gates run against.
func (e *emittedOps) records() []adapterkit.OpRecord {
	out := make([]adapterkit.OpRecord, 0, len(e.ops))
	for _, op := range e.ops {
		out = append(out, adapterkit.OpRecord{Op: op.OpKind(), Path: op.OpPath()})
	}
	return out
}

// wireOps marshals each accumulated op to its wire envelope for
// EmitResult.Ops, in the same order as records(). This carries the op
// content to the CLI core, which performs the actual writes
// (invariant #2). Decoded caller-side via contract.DecodeOp.
func (e *emittedOps) wireOps() ([]json.RawMessage, error) {
	out := make([]json.RawMessage, 0, len(e.ops))
	for _, op := range e.ops {
		raw, err := json.Marshal(op)
		if err != nil {
			return nil, fmt.Errorf("cursor: marshal op %s %q: %w", op.OpKind(), op.OpPath(), err)
		}
		out = append(out, raw)
	}
	return out, nil
}

// handleEmit is the OnEmit handler the bundled adapter registers.
// Decodes the IR document, dispatches each node by kind, and returns
// the accumulated OpRecord summary.
//
// One-failed-node-fails-the-emit is the v1 behavior: if any node
// produces an error, the whole call returns that error and partially
// emitted ops are discarded. Per-node skip-with-warning is a Unit 8b
// extension.
//
// Context is checked between nodes so a runtime cancel during a
// large IR is honored without waiting for the full iteration.
func handleEmit(ctx context.Context, params adapterkit.EmitParams, scope, sourceURL, sourceCommit string) (adapterkit.EmitResult, error) {
	doc, err := decodeIRDocument(params.IR)
	if err != nil {
		return adapterkit.EmitResult{}, &adapterkit.Error{
			Code:    adapterkit.CodeInvalidParams,
			Message: fmt.Sprintf("cursor: %s", err.Error()),
		}
	}

	// Detect duplicate (kind, id) pairs in the wire payload before
	// emitting. The IR decoder enforces uniqueness on its own output
	// but the wire shape can carry duplicates from a buggy or
	// adversarial producer; emitting the same path twice would let
	// the sync engine silently last-write-wins.
	if err := rejectDuplicateNodes(doc.Nodes); err != nil {
		return adapterkit.EmitResult{}, err
	}

	emitted := &emittedOps{}

	// readmeEmitted dedups per-subdir mkdir+README pairs.
	// sidecarEmitted dedups the .agent-sync-managed sidecar (only ever
	// written next to .cursor/mcp.json; one per emit regardless of how
	// many mcp-server-entry nodes are present).
	state := emitState{
		sourceURL:       sourceURL,
		sourceCommit:    sourceCommit,
		readmeEmitted:   map[string]bool{},
		sidecarEmitted:  false,
		emittedFilePath: map[string]struct{}{},
		paths:           resolvePathSet(scope),
		atUserScope:     scope == scopeUser,
	}

	// Iterate in a deterministic order (sorted by kind, then id) so
	// op output is stable across runs and easy to compare against
	// fixtures. The IR decoder upstream already sorts the same way,
	// but we re-sort defensively in case a malformed decoder ships
	// nodes in arbitrary order.
	slices.SortFunc(doc.Nodes, func(a, b irNode) int {
		if c := cmp.Compare(a.Kind, b.Kind); c != 0 {
			return c
		}
		return cmp.Compare(a.ID, b.ID)
	})

	for _, node := range doc.Nodes {
		if err := ctx.Err(); err != nil {
			return adapterkit.EmitResult{}, &adapterkit.Error{
				Code:    adapterkit.CodeInternalError,
				Message: fmt.Sprintf("cursor: emit cancelled: %s", err.Error()),
			}
		}
		if !nodeTargetsCursor(node) {
			// Node is targeted at a different adapter — silent skip.
			continue
		}
		if err := dispatchNode(emitted, node, &state); err != nil {
			return adapterkit.EmitResult{}, err
		}
	}

	wire, err := emitted.wireOps()
	if err != nil {
		return adapterkit.EmitResult{}, &adapterkit.Error{
			Code:    adapterkit.CodeInternalError,
			Message: err.Error(),
		}
	}
	return adapterkit.EmitResult{OpsPerformed: emitted.records(), Ops: wire}, nil
}

// emitState carries per-emit dedup tables. Threading one struct
// instead of multiple maps keeps dispatchNode's signature stable as
// new dedup keys appear.
//
// emittedFilePath records every workspace-relative path that's been
// emitted as a write_file in this call. When two ops would target
// the same path the dispatcher fails closed instead of letting the
// sync engine last-write-wins.
type emitState struct {
	// sourceURL / sourceCommit are the session-level source identity from
	// InitializeParams (audit-safe canonical URL or local path + resolved
	// SHA), used to render the managed header. A node-level override
	// (composed nodes) wins over these — see prependHeader.
	sourceURL    string
	sourceCommit string

	readmeEmitted   map[string]bool
	sidecarEmitted  bool
	emittedFilePath map[string]struct{}
	// paths are the scope-resolved tool-owned destinations (.cursor/mcp.json +
	// sidecar at project scope; sidecar suppressed at user scope). Resolved once
	// per emit from the initialize scope.
	paths pathSet
	// atUserScope is true when the initialize scope is the user-home scope.
	// rule and agents-md have no file-addressable user-global home in Cursor, so
	// dispatchNode skips them at user scope (internal/coverage emits the
	// user-facing warning). See plan docs/plans/2026-06-30-001.
	atUserScope bool
}

// recordWritePath registers a write_file path in the per-emit dedup
// table. Returns an InvalidParams error when the path was already
// emitted earlier in this call. Callers should check before
// constructing the OpWriteFile so the error message can include
// node-level context.
func (s *emitState) recordWritePath(path string) error {
	if _, exists := s.emittedFilePath[path]; exists {
		return &adapterkit.Error{
			Code:    adapterkit.CodeInvalidParams,
			Message: fmt.Sprintf("cursor: duplicate write_file path %q in single emit", path),
		}
	}
	s.emittedFilePath[path] = struct{}{}
	return nil
}

// dispatchNode routes one IR node to its kind-specific emitter.
//
// Supported kinds (rule, mcp-server-entry, agents-md) produce ops;
// unsupported kinds (skill, command, plugin-reference) produce a
// degradation warning and emit no files. The capability matrix in
// capabilities.go is the authoritative source for which kinds are
// supported; this switch must stay in agreement with it.
//
// At user scope, rule and agents-md are skipped (no op): Cursor has no
// file-addressable user-global home for either (User Rules live in app
// settings / cloud; there is no global AGENTS.md), so writing them under
// ~/.cursor/ or ~/AGENTS.md would be inert. internal/coverage emits the
// user-facing warning for these (computed from the manifest), so the adapter
// stays silent here to avoid a double warning.
//
// The silent skip is only safe because capabilitiesForWire declares rule and
// agents-md UNSUPPORTED at user scope: the runtime's capability-lied gate fails
// any session that declares a kind supported but emits zero non-warning ops for
// an in-target node of that kind. A user-scope manifest with only a rule (no
// MCP entry) is exactly that case — the unsupported declaration keeps it an
// honest no-op instead of a sync failure. See capabilitiesForWire and plan
// docs/plans/2026-06-30-001.
func dispatchNode(emitted *emittedOps, node irNode, state *emitState) error {
	if !ir.IsValidID(node.ID) {
		return &adapterkit.Error{
			Code:    adapterkit.CodeInvalidParams,
			Message: fmt.Sprintf("cursor: invalid node id %q", node.ID),
		}
	}
	switch ir.Kind(node.Kind) {
	case ir.KindRule:
		if state.atUserScope {
			return nil // no user-global rules home; see coverage.nonNativeAtUser
		}
		return emitRule(emitted, node, state)
	case ir.KindMCPServerEntry:
		return emitMCPServerEntry(emitted, node, state)
	case ir.KindAgentsMD:
		if state.atUserScope {
			return nil // no user-global AGENTS.md home; see coverage.nonNativeAtUser
		}
		return emitAgentsMD(emitted, node)
	case ir.KindSkill, ir.KindCommand, ir.KindPluginReference:
		return emitUnsupportedWarning(emitted, node)
	default:
		return &adapterkit.Error{
			Code:    adapterkit.CodeInvalidParams,
			Message: fmt.Sprintf("cursor: unknown IR kind %q for node %q", node.Kind, node.ID),
		}
	}
}

// decodeIRDocument unmarshals the EmitParams.IR raw message. Returns
// a wrapped error on parse failure so handleEmit can convert it to a
// JSON-RPC InvalidParams response.
func decodeIRDocument(raw json.RawMessage) (irDocument, error) {
	if len(raw) == 0 {
		return irDocument{}, nil
	}
	var doc irDocument
	if err := json.Unmarshal(raw, &doc); err != nil {
		return irDocument{}, fmt.Errorf("decode IR document: %w", err)
	}
	return doc, nil
}

// nodeTargetsCursor reports whether the node's targets list either
// is empty (means "all adapters") or includes the cursor adapter.
// IR-side validation guarantees the contained values are known
// adapter names; we don't re-validate here.
func nodeTargetsCursor(node irNode) bool {
	if len(node.Targets) == 0 {
		return true
	}
	for _, t := range node.Targets {
		if t == adapterName {
			return true
		}
	}
	return false
}

// rejectDuplicateNodes returns InvalidParams when the wire payload
// contains two or more nodes with the same (kind, id) pair. The
// fail-closed default avoids the silent last-write-wins behavior the
// sync engine would otherwise hit at write time.
func rejectDuplicateNodes(nodes []irNode) error {
	seen := make(map[string]struct{}, len(nodes))
	for _, n := range nodes {
		key := n.Kind + "/" + n.ID
		if _, dup := seen[key]; dup {
			return &adapterkit.Error{
				Code:    adapterkit.CodeInvalidParams,
				Message: fmt.Sprintf("cursor: duplicate node (kind=%q id=%q) in IR payload", n.Kind, n.ID),
			}
		}
		seen[key] = struct{}{}
	}
	return nil
}

// decodeBodyOrPassthrough turns a node or asset Body field into raw
// bytes. The wire shape allows two body encodings:
//   - JSON string (markdown bodies): `"# heading\n..."`
//   - Raw JSON value (json/toml kinds): `{"command":"node",...}`
//
// String-decode is tried first; if that fails the raw JSON value is
// validated and passed through unchanged.
func decodeBodyOrPassthrough(raw json.RawMessage) ([]byte, error) {
	if len(raw) == 0 || string(raw) == "null" {
		return nil, nil
	}
	var s string
	if err := json.Unmarshal(raw, &s); err == nil {
		return []byte(s), nil
	}
	var any any
	if err := json.Unmarshal(raw, &any); err != nil {
		return nil, fmt.Errorf("body must be a JSON string or valid JSON value: %w", err)
	}
	return raw, nil
}

// wrapBodyErr converts a node-body decode error into the structured
// JSON-RPC error the caller returns.
func wrapBodyErr(node irNode, err error) error {
	return &adapterkit.Error{
		Code:    adapterkit.CodeInvalidParams,
		Message: fmt.Sprintf("cursor: node %q (%s) body: %s", node.ID, node.Kind, err.Error()),
	}
}

// wrapOpErr converts an op-construction error (typically the
// payload-too-large guard inside NewOpWriteFile) into the structured
// JSON-RPC error the caller returns.
func wrapOpErr(node irNode, err error) error {
	return &adapterkit.Error{
		Code:    adapterkit.CodeInvalidParams,
		Message: fmt.Sprintf("cursor: node %q (%s) op: %s", node.ID, node.Kind, err.Error()),
	}
}

package cursor

import (
	"fmt"

	"github.com/agent-sync/agent-sync/internal/ir"
	"github.com/agent-sync/agent-sync/pkg/adapterkit"
)

// unsupportedNotes maps each unsupported IR kind to its user-facing
// degradation note. Cursor reads none of these at the project level;
// the adapter declines honestly rather than emitting dead files into
// directories Cursor never reads.
var unsupportedNotes = map[ir.Kind]string{
	ir.KindSkill:           "Cursor has no folder-per-skill concept; skills are not installed at the project level",
	ir.KindCommand:         "Cursor has no project-level custom command concept; the command was not installed",
	ir.KindPluginReference: "Cursor does not load project-level plugin references; the reference was not installed",
}

// emitUnsupportedWarning surfaces the unsupported declaration for a
// skill, command, or plugin-reference node. No write_file is emitted.
//
// The runtime's capability-lied check (internal/adapter/runtime.go)
// only fires for kinds the adapter declared as `supported`, so
// emitting a warning-only result here is safe — all three kinds are
// declared `unsupported` in capabilities.yaml.
func emitUnsupportedWarning(emitted *emittedOps, node irNode) error {
	note, ok := unsupportedNotes[ir.Kind(node.Kind)]
	if !ok {
		// Defensive: dispatchNode only routes the three unsupported
		// kinds here, so an unmapped kind is a programming error
		// (a new unsupported kind added to the switch but not the
		// note table). Fail loudly rather than emit an empty note.
		return &adapterkit.Error{
			Code:    adapterkit.CodeInternalError,
			Message: fmt.Sprintf("cursor: no unsupported-note for kind %q (node %q)", node.Kind, node.ID),
		}
	}
	emitted.add(adapterkit.OpWarning{
		ConceptID: node.ID,
		Status:    adapterkit.WarningStatusDegraded,
		Note:      note,
	})
	return nil
}

package cursor

import (
	_ "embed"
	"fmt"

	"github.com/goccy/go-yaml"

	"github.com/agent-sync/agent-sync/internal/capmatrix"
	"github.com/agent-sync/agent-sync/internal/ir"
	"github.com/agent-sync/agent-sync/pkg/adapterkit"
)

//go:embed capabilities.yaml
var capabilitiesYAML []byte

// declarationFile is the parsed shape of capabilities.yaml. It is
// intentionally narrower than adapter.AdapterManifest so the file
// stays a per-adapter declaration and not an arbitrary manifest
// override.
type declarationFile struct {
	Name            string                            `yaml:"name"`
	Version         string                            `yaml:"version"`
	ContractVersion string                            `yaml:"contract_version"`
	ReservedPrefix  string                            `yaml:"reserved_prefix"`
	ConceptKinds    map[string]conceptKindDeclaration `yaml:"concept_kinds"`
}

type conceptKindDeclaration struct {
	Status capmatrix.CapabilityStatus `yaml:"status"`
	Note   string                     `yaml:"note,omitempty"`
}

// conceptKinds is the in-code mirror of capabilities.yaml. The unit
// test asserts the two are kept in sync; if you add a kind here,
// add it there (and vice versa).
//
// Cursor declares three kinds unsupported: skill (no folder-per-skill
// concept), command (no project-level command concept), and
// plugin-reference (no project plugin registry). See capabilities.yaml
// notes and docs/adapters/cursor.md for the rationale.
var conceptKinds = map[ir.Kind]capmatrix.CapabilityStatus{
	ir.KindAgentsMD:        capmatrix.Supported,
	ir.KindRule:            capmatrix.Supported,
	ir.KindMCPServerEntry:  capmatrix.Supported,
	ir.KindSkill:           capmatrix.Unsupported,
	ir.KindCommand:         capmatrix.Unsupported,
	ir.KindPluginReference: capmatrix.Unsupported,
}

// capabilitiesForWire returns the adapterkit.Capabilities the adapter
// echoes in its initialize response. WriteToolOwned is true because
// the cursor adapter emits write_tool_owned ops for .cursor/mcp.json
// and AGENTS.md.
//
// The set is scope-aware. At user scope, rule and agents-md are declared
// UNSUPPORTED: Cursor has no file-addressable user-global home for either
// (User Rules are app-settings/cloud; there is no global AGENTS.md), so
// dispatchNode skips them. Declaring them unsupported — rather than leaving
// them "supported" while emitting nothing — is load-bearing: the runtime's
// capability-lied gate (runtime.go) fails any session that declares a kind
// supported, receives an in-target node of that kind, and emits zero
// non-warning ops. A user-scope manifest targeting Cursor with only a rule
// (no MCP entry) hits exactly that case, so the declaration must match the
// emit reality. See dispatchNode + plan docs/plans/2026-06-30-001.
func capabilitiesForWire(scope string) adapterkit.Capabilities {
	builder := adapterkit.NewCapabilities().WithWriteToolOwned(true)
	for kind, status := range conceptKinds {
		if scope == scopeUser && (kind == ir.KindRule || kind == ir.KindAgentsMD) {
			builder.Unsupported(string(kind))
			continue
		}
		switch status {
		case capmatrix.Supported:
			builder.Supports(string(kind))
		case capmatrix.Partial:
			builder.Partial(string(kind))
		case capmatrix.Unsupported:
			builder.Unsupported(string(kind))
		}
	}
	return builder.Build()
}

// declaredOutputs returns the list the adapter advertises in its
// initialize response. The runtime path-safety gate
// (internal/adapter/runtime.go pathInDeclaredOutputs) accepts an
// emitted op only when its path falls inside one of these declared
// outputs.
//
// The set is scope-aware. At user scope only .cursor/mcp.json is declared:
// it is the sole file-addressable user-global Cursor config (~/.cursor/mcp.json),
// the sidecar is suppressed (the global mcp.json is Cursor's own file), and
// rules / AGENTS.md have no user-global home so they are neither declared nor
// emitted (see emit.go dispatchNode and coverage.nonNativeAtUser). Paths come
// from resolvePathSet so declared and emitted paths never drift. See plan
// docs/plans/2026-06-30-001.
func declaredOutputs(scope string) []adapterkit.DeclaredOutput {
	mcpPointer := "/mcpServers"
	paths := resolvePathSet(scope)
	outputs := []adapterkit.DeclaredOutput{
		{Path: paths.mcpJSON, Mode: adapterkit.OutputModeToolOwnedEntry, JSONPointer: &mcpPointer},
	}
	if scope == scopeUser {
		return outputs
	}
	agentsMDSection := "agent-sync"
	outputs = append(outputs,
		adapterkit.DeclaredOutput{Path: ".cursor/rules/agent-sync", Mode: adapterkit.OutputModeOwnedSubdir},
		adapterkit.DeclaredOutput{Path: agentsMDPath, Mode: adapterkit.OutputModeToolOwnedEntry, SectionID: &agentsMDSection},
		// The strict-JSON sidecar marker (.agent-sync-managed) is written
		// next to .cursor/mcp.json under .cursor/. Declared by exact
		// path (owned-subdir mode authorizes the path; the write_file
		// op writes it) rather than over-broadly authorizing .cursor/.
		adapterkit.DeclaredOutput{Path: paths.sidecar, Mode: adapterkit.OutputModeOwnedSubdir},
	)
	return outputs
}

// parseCapabilitiesYAML decodes the embedded YAML. Used by the parity
// test and by callers that want the human-readable note bodies.
func parseCapabilitiesYAML(src []byte) (declarationFile, error) {
	var d declarationFile
	if err := yaml.UnmarshalWithOptions(
		src,
		&d,
		yaml.DisallowUnknownField(),
		yaml.AllowFieldPrefixes("x-"),
	); err != nil {
		return declarationFile{}, fmt.Errorf("cursor: parse capabilities.yaml: %s", yaml.FormatError(err, false, true))
	}
	return d, nil
}

// loadDeclaration parses the embedded capabilities.yaml and returns
// the result.
func loadDeclaration() (declarationFile, error) {
	return parseCapabilitiesYAML(capabilitiesYAML)
}

package cursor

import (
	"fmt"
	"strings"
)

// managedHeaderTemplate is the canonical "do not edit" banner the
// cursor adapter prepends to every owned markdown / .mdc file. The
// {source-url} and {short-sha} placeholders are filled in by the
// sync engine (Unit 13) once it plumbs IR-decode context through
// EmitParams._meta. v1 ships the placeholder so the line shape is
// stable from day one.
//
// For v1 the emitted .mdc files carry no frontmatter (the IR strips
// it at decode), so a leading HTML comment is safe — it does not
// displace a `---` frontmatter opener off line 1.
//
// renderManagedHeader renders the "do not edit" banner with real
// provenance (plan U3). sourceURL is the audit-safe source identity —
// the cache-canonicalized git URL or a local source path — from the
// session, or a per-node override for composed nodes. sourceCommit is
// the resolved canonical SHA, empty for working-tree sources. Forms:
//
//	git-backed: <!-- … Source: <url>@<sha12>. Regenerate: … -->
//	local:      <!-- … Source: <path>. Regenerate: … -->
//	no source:  <!-- … Regenerate: … --> (defensive; a session from a
//	            pre-U2 engine carries no source identity)
//
// The trailing blank line keeps a one-line gap between the header and
// user-visible content. BYTE-IDENTITY: codex and pi must render the
// exact same bytes for the same inputs — the shared .agents/skills
// tree is co-emitted (ADV-1) and the engine fail-closes on divergence.
func renderManagedHeader(sourceURL, sourceCommit string) []byte {
	const pre = "<!-- Managed by agent-sync — do not edit. "
	const post = "Regenerate: agent-sync sync -->\n\n"
	switch {
	case sourceURL == "":
		return []byte(pre + post)
	case sourceCommit == "":
		return []byte(pre + "Source: " + sourceURL + ". " + post)
	default:
		return []byte(pre + "Source: " + sourceURL + "@" + shortSHA(sourceCommit) + ". " + post)
	}
}

// shortSHA truncates a full commit SHA to git's collision-safe 12-char
// display form; shorter inputs pass through unchanged.
func shortSHA(sha string) string {
	if len(sha) > 12 {
		return sha[:12]
	}
	return sha
}

// jsonSidecarBody is the body for the .agent-sync-managed sidecar marker
// the cursor adapter writes next to .cursor/mcp.json. JSON has no
// comment syntax, so the sidecar advertises ownership instead of
// editing the JSON file with a comment.
//
// The body is intentionally short and human-readable; it is not
// machine-parsed by anything in v1.
const jsonSidecarBody = `Managed by agent-sync.

The sibling .cursor/mcp.json file contains entries owned by agent-sync
under the /mcpServers/agentsync_<id> JSON pointers. Other entries are
preserved across syncs.

To remove agent-sync-managed entries: agent-sync unmanage cursor
`

// jsonSidecarMarker returns the body for the .agent-sync-managed sidecar
// marker placed next to strict-JSON tool-owned files (currently just
// .cursor/mcp.json). See managedHeaderTemplate doc for why JSON gets
// a sidecar instead of an inline comment.
func jsonSidecarMarker() []byte {
	return []byte(jsonSidecarBody)
}

// readmeForSubdir returns the README.md body the cursor adapter
// emits into each reserved subdirectory. The README explains
// ownership and the exit path so a human stumbling into
// .cursor/rules/agent-sync/README.md knows it isn't user content.
//
// subdirLabel is the relative path used inside the body for clarity
// (e.g., ".cursor/rules/agent-sync"); pass the same string used in the
// declared output.
func readmeForSubdir(subdirLabel string) []byte {
	subdirLabel = strings.TrimSpace(subdirLabel)
	if subdirLabel == "" {
		// Defensive default. Empty subdirLabel is a programmer error;
		// an empty README is less harmful than a panic during a sync
		// that's already trying to recover.
		subdirLabel = "(unknown subdirectory)"
	}
	return fmt.Appendf(nil,
		"# Managed by agent-sync\n\n"+
			"Files inside `%s/` are owned by the agent-sync `cursor` adapter.\n"+
			"Editing them by hand is detected as drift on the next sync\n"+
			"and the changes are overwritten.\n\n"+
			"To remove every agent-sync-owned file in this directory and\n"+
			"unbind it from the workspace, run:\n\n"+
			"    agent-sync unmanage cursor\n",
		subdirLabel,
	)
}

package cursor

import (
	"fmt"

	"github.com/agent-sync/agent-sync/pkg/adapterkit"
)

const (
	rulesSubdir = ".cursor/rules/agent-sync"
	mdcExt      = ".mdc"
)

// emitRule maps one rule node to:
//   - mkdir(.cursor/rules/agent-sync)               (deduped per-emit)
//   - write_file(.cursor/rules/agent-sync/README.md) (deduped per-emit)
//   - write_file(.cursor/rules/agent-sync/<id>.mdc)
//
// Unlike the claude adapter, there is no `paths:` frontmatter ward:
// that warning exists for a Claude Code activation bug with no Cursor
// equivalent (Cursor's .mdc frontmatter supports globs/description/
// alwaysApply natively). v1 emits frontmatter-less .mdc files because
// the IR strips frontmatter at decode; they behave as manual /
// agent-requested rules until IR frontmatter exposure lands.
//
// Cursor reads project rules from .cursor/rules/ as .mdc files and
// supports nested subdirectories, which is what makes the agent-sync/
// subfolder a valid owned subdirectory.
func emitRule(emitted *emittedOps, node irNode, state *emitState) error {
	body, err := decodeBodyOrPassthrough(node.Body)
	if err != nil {
		return wrapBodyErr(node, err)
	}

	if err := ensureSubdir(emitted, rulesSubdir, state); err != nil {
		return err
	}

	rulePath := rulesSubdir + "/" + node.ID + mdcExt
	if err := state.recordWritePath(rulePath); err != nil {
		return err
	}
	wf, err := adapterkit.NewOpWriteFile(rulePath, 0o644, prependHeader(state, node, body))
	if err != nil {
		return wrapOpErr(node, err)
	}
	emitted.add(wf)
	return nil
}

// ensureSubdir adds the per-emit mkdir + README pair for a reserved
// subdirectory once per emit call. Subsequent calls are no-ops.
//
// Returns InvalidParams if a node ID has already taken the README
// path inside this subdir (e.g., a rule node literally named "README"
// — its emitted path would be .../agent-sync/README.mdc, which does not
// collide, but the README.md guard still protects the reserved file).
func ensureSubdir(emitted *emittedOps, subdir string, state *emitState) error {
	if state.readmeEmitted[subdir] {
		return nil
	}
	state.readmeEmitted[subdir] = true
	emitted.add(adapterkit.OpMkdir{Path: subdir, Mode: 0o755})
	readmePath := subdir + "/README.md"
	if err := state.recordWritePath(readmePath); err != nil {
		return err
	}
	wf, err := adapterkit.NewOpWriteFile(readmePath, 0o644, readmeForSubdir(subdir))
	if err != nil {
		// readmeForSubdir returns a small fixed body; the only way
		// NewOpWriteFile can fail is the payload-too-large guard,
		// which is unreachable here. Panic surfaces the bug.
		panic(fmt.Sprintf("cursor: building README for %s: %v", subdir, err))
	}
	emitted.add(wf)
	return nil
}

// prependHeader inserts the managed-file header before the body. The
// header carries per-node provenance when the node has a source
// override (composed nodes); otherwise the session-level source.
func prependHeader(state *emitState, node irNode, body []byte) []byte {
	url, commit := state.sourceURL, state.sourceCommit
	if node.SourceURL != "" {
		url, commit = node.SourceURL, node.SourceCommit
	}
	header := renderManagedHeader(url, commit)
	out := make([]byte, 0, len(header)+len(body))
	out = append(out, header...)
	out = append(out, body...)
	return out
}

