251	func TestRun_InitializeRoundTrip(t *testing.T) {
252		t.Parallel()
253	
254		server := adapterkit.NewServer(adapterkit.ServerOptions{
255			Name:    adapterName,
256			Version: adapterVersion,
257		})
258		var scope string
259		server.OnInitialize(func(_ context.Context, params adapterkit.InitializeParams) (adapterkit.InitializeResult, error) {
260			scope = params.Scope
261			return adapterkit.InitializeResult{
262				Capabilities:    capabilitiesForWire(scope),
263				DeclaredOutputs: declaredOutputs(scope),
264			}, nil
265		})
266		server.OnEmit(func(ctx context.Context, params adapterkit.EmitParams) (adapterkit.EmitResult, error) {
267			return handleEmit(ctx, params, scope, "", "")
268		})
269	
270		client, cleanup := adapterkit.RunInprocServer(t, server)
271		t.Cleanup(cleanup)
272	
273		ctx := context.Background()
274		res, err := client.Initialize(ctx, adapterkit.InitializeParams{
275			Client:           "test",
276			ProtocolVersions: []string{adapterkit.ContractVersionV1},
277			Cookie:           "00000000000000000000000000000000",
278			WorkspaceRoot:    t.TempDir(),
279			ReservedPrefix:   reservedPrefix,
280			IRVersion:        "v1",
281		})
282		if err != nil {
283			t.Fatalf("Initialize: %v", err)
284		}
285		if res.ProtocolVersion != adapterkit.ContractVersionV1 {
286			t.Errorf("ProtocolVersion=%q want %q", res.ProtocolVersion, adapterkit.ContractVersionV1)
287		}
288		if got, want := len(res.DeclaredOutputs), len(declaredOutputs("project")); got != want {
289			t.Errorf("DeclaredOutputs len=%d want %d", got, want)
290		}
291		if !res.Capabilities.WriteToolOwned {
292			t.Error("WriteToolOwned not echoed back")
293		}
294		if err := client.Initialized(ctx); err != nil {
295			t.Fatalf("Initialized: %v", err)
296		}
297		emit, err := client.Emit(ctx, adapterkit.EmitParams{Target: adapterName})
298		if err != nil {
299			t.Fatalf("Emit: %v", err)
300		}
301		if len(emit.OpsPerformed) != 0 {
302			t.Errorf("scaffold Emit OpsPerformed should be empty; got %v", emit.OpsPerformed)
303		}
304		if err := client.Shutdown(ctx); err != nil {
305			t.Fatalf("Shutdown: %v", err)
306		}
307	}
308	
309	func equalStringSlices(a, b []string) bool {
310		if len(a) != len(b) {
311			return false
312		}
313		for i := range a {
314			if a[i] != b[i] {
315				return false
316			}
317		}
318		return true
319	}
